import type { BibleVerse } from '../bibleData';

export const GENESIS_CH32_50: Record<number, BibleVerse[]> = {
  32: [
    { v: 1, en: 'And Jacob went on his way, and the angels of God met him.', pt: 'Jacó também seguiu o seu caminho, e os anjos de Deus o encontraram.' },
    { v: 2, en: 'And when Jacob saw them, he said, This is God\'s host: and he called the name of that place Mahanaim.', pt: 'Quando Jacó os viu, disse: Este é o exército de Deus. E chamou aquele lugar Maanaim.' },
    { v: 3, en: 'And Jacob sent messengers before him to Esau his brother unto the land of Seir, the country of Edom.', pt: 'Jacó enviou mensageiros adiante de si a Esaú, seu irmão, à terra de Seir, ao território de Edom.' },
    { v: 4, en: 'And he commanded them, saying, Thus shall ye speak unto my lord Esau; Thy servant Jacob saith thus, I have sojourned with Laban, and stayed there until now:', pt: 'E lhes ordenou: Assim direis a meu senhor Esaú: O teu servo Jacó diz assim: Tenho morado com Labão, e ficado até agora.' },
    { v: 5, en: 'And I have oxen, and asses, flocks, and menservants, and womenservants: and I have sent to tell my lord, that I may find grace in thy sight.', pt: 'Tenho bois, jumentos, ovelhas, servos e servas; e enviei a meu senhor esta mensagem, para achar graça aos teus olhos.' },
    { v: 6, en: 'And the messengers returned to Jacob, saying, We came to thy brother Esau, and also he cometh to meet thee, and four hundred men with him.', pt: 'Os mensageiros voltaram a Jacó, dizendo: Fomos a teu irmão Esaú, e ele também vem ao teu encontro com quatrocentos homens.' },
    { v: 7, en: 'Then Jacob was greatly afraid and distressed: and he divided the people that was with him, and the flocks, and herds, and the camels, into two bands;', pt: 'Jacó ficou com muito medo e angustiado; dividiu o povo que estava com ele, os rebanhos, o gado e os camelos, em dois grupos,' },
    { v: 8, en: 'And said, If Esau come to the one company, and smite it, then the other company which is left shall escape.', pt: 'dizendo: Se Esaú vier a um grupo e o atacar, o outro grupo poderá escapar.' },
    { v: 9, en: 'And Jacob said, O God of my father Abraham, and God of my father Isaac, the LORD which saidst unto me, Return unto thy country, and to thy kindred, and I will deal well with thee:', pt: 'Então Jacó orou: Ó Deus de meu pai Abraão, e Deus de meu pai Isaque, Senhor que me disseste: Volta à tua terra e à tua parentela, e eu farei bem a ti,' },
    { v: 10, en: 'I am not worthy of the least of all the mercies, and of all the truth, which thou hast shewed unto thy servant; for with my staff I passed over this Jordan; and now I am become two bands.', pt: 'não mereço nenhuma das misericórdias nem de toda a fidelidade que tens mostrado ao teu servo; pois com o meu cajado passei este Jordão, e agora me tornei dois grupos.' },
    { v: 11, en: 'Deliver me, I pray thee, from the hand of my brother, from the hand of Esau: for I fear him, lest he will come and smite me, and the mother with the children.', pt: 'Livra-me, eu te peço, da mão de meu irmão, da mão de Esaú; pois temo que ele venha e me ataque, à mãe com os filhos.' },
    { v: 12, en: 'And thou saidst, I will surely do thee good, and make thy seed as the sand of the sea, which cannot be numbered for multitude.', pt: 'Tu disseste: Certamente farei bem a ti, e tornarei a tua descendência como a areia do mar, que não pode ser contada pela sua multidão.' },
    { v: 13, en: 'And he lodged there that same night; and took of that which came to his hand a present for Esau his brother;', pt: 'Ali pernoitou aquela noite, e do que tinha à mão separou um presente para Esaú, seu irmão:' },
    { v: 14, en: 'Two hundred she goats, and twenty he goats, two hundred ewes, and twenty rams,', pt: 'duzentas cabras e vinte bodes, duzentas ovelhas e vinte carneiros,' },
    { v: 15, en: 'Thirty milch camels with their colts, forty kine, and ten bulls, twenty she asses, and ten foals.', pt: 'trinta camelas amamentando com seus filhotes, quarenta vacas e dez touros, vinte jumentas e dez jumentos.' },
    { v: 16, en: 'And he delivered them into the hand of his servants, every drove by themselves; and said unto his servants, Pass over before me, and put a space betwixt drove and drove.', pt: 'Entregou-os nas mãos dos seus servos, cada manada separadamente, e disse aos seus servos: Passai adiante de mim e deixai espaço entre manada e manada.' },
    { v: 17, en: 'And he commanded the foremost, saying, When Esau my brother meeteth thee, and asketh thee, saying, Whose art thou? and whither goest thou? and whose are these before thee?', pt: 'Ordenou ao primeiro: Quando Esaú, meu irmão, te encontrar e te perguntar: De quem és? Para onde vais? e de quem são esses animais que vão à tua frente?' },
    { v: 18, en: 'Then thou shalt say, They be thy servant Jacob\'s; it is a present sent unto my lord Esau: and, behold, also he is behind us.', pt: 'então dirás: São do teu servo Jacó; é um presente enviado a meu senhor Esaú; e ele mesmo vem atrás de nós.' },
    { v: 19, en: 'And so commanded he the second, and the third, and all that followed the droves, saying, On this manner shall ye speak unto Esau, when ye find him.', pt: 'Ordenou também ao segundo, ao terceiro, e a todos que seguiam as manadas: Assim falareis a Esaú quando o encontrardes.' },
    { v: 20, en: 'And say ye moreover, Behold, thy servant Jacob is behind us. For he said, I will appease him with the present that goeth before me, and afterward I will see his face; peradventure he will accept of me.', pt: 'E direis também: Eis que o teu servo Jacó vem atrás de nós. Pois ele disse: Vou aplacá-lo com o presente que vai adiante de mim, e depois verei o seu rosto; talvez me receba favoravelmente.' },
    { v: 21, en: 'So went the present over before him: and himself lodged that night in the company.', pt: 'Assim o presente passou adiante dele, e ele passou aquela noite no acampamento.' },
    { v: 22, en: 'And he rose up that night, and took his two wives, and his two womenservants, and his eleven sons, and passed over the ford Jabbok.', pt: 'Aquela noite, levantou-se e tomou suas duas mulheres, suas duas servas e seus onze filhos, e atravessou o vau do Jaboque.' },
    { v: 23, en: 'And he took them, and sent them over the brook, and sent over that he had.', pt: 'Tomou-os e fez-os atravessar o ribeiro, e fez passar também tudo o que tinha.' },
    { v: 24, en: 'And Jacob was left alone; and there wrestled a man with him until the breaking of the day.', pt: 'Jacó ficou sozinho, e um homem lutou com ele até ao romper da alva.' },
    { v: 25, en: 'And when he saw that he prevailed not against him, he touched the hollow of his thigh; and the hollow of Jacob\'s thigh was out of joint, as he wrestled with him.', pt: 'Quando viu que não prevalecia contra ele, tocou a articulação da sua coxa; e a articulação da coxa de Jacó se deslocou enquanto lutava com ele.' },
    { v: 26, en: 'And he said, Let me go, for the day breaketh. And he said, I will not let thee go, except thou bless me.', pt: 'Então disse: Deixa-me ir, porque já raiou a alva. Mas Jacó respondeu: Não te deixarei ir, senão quando me abençoares.' },
    { v: 27, en: 'And he said unto him, What is thy name? And he said, Jacob.', pt: 'Perguntou-lhe: Qual é o teu nome? Respondeu: Jacó.' },
    { v: 28, en: 'And he said, Thy name shall be called no more Jacob, but Israel: for as a prince hast thou power with God and with men, and hast prevailed.', pt: 'Disse-lhe: O teu nome não será mais Jacó, mas Israel; porque lutaste com Deus e com os homens, e prevaleceste.' },
    { v: 29, en: 'And Jacob asked him, and said, Tell me, I pray thee, thy name. And he said, Wherefore is it that thou dost ask after my name? And he blessed him there.', pt: 'Jacó perguntou: Dize-me o teu nome, por favor. Ele respondeu: Por que perguntas o meu nome? E o abençoou ali.' },
    { v: 30, en: 'And Jacob called the name of the place Peniel: for I have seen God face to face, and my life is preserved.', pt: 'Jacó chamou aquele lugar Peniel, dizendo: Vi a Deus face a face, e ainda assim a minha vida foi preservada.' },
    { v: 31, en: 'And as he passed over Penuel the sun rose upon him, and he halted upon his thigh.', pt: 'O sol se levantou sobre ele quando passava por Penuel, e Jacó coxeava por causa da sua coxa.' },
    { v: 32, en: 'Therefore the children of Israel eat not of the sinew which shrank, which is upon the hollow of the thigh, unto this day: because he touched the hollow of Jacob\'s thigh in the sinew that shrank.', pt: 'Por isso os filhos de Israel não comem até hoje o nervo encolhido que está na articulação da coxa, porque ele tocou a articulação da coxa de Jacó no nervo encolhido.' },
  ],
  33: [
    { v: 1, en: 'And Jacob lifted up his eyes, and looked, and, behold, Esau came, and with him four hundred men. And he divided the children unto Leah, and unto Rachel, and unto the two handmaids.', pt: 'Jacó levantou os seus olhos e viu que Esaú vinha com quatrocentos homens. Então distribuiu os filhos entre Lia, Raquel e as duas servas.' },
    { v: 2, en: 'And he put the handmaids and their children foremost, and Leah and her children after, and Rachel and Joseph hindermost.', pt: 'Pôs as servas e seus filhos na frente, Lia e seus filhos depois, e Raquel e José por último.' },
    { v: 3, en: 'And he passed over before them, and bowed himself to the ground seven times, until he came near to his brother.', pt: 'Ele mesmo passou à frente deles, e foi se inclinando até ao chão sete vezes, até chegar perto de seu irmão.' },
    { v: 4, en: 'And Esau ran to meet him, and embraced him, and fell on his neck, and kissed him: and they wept.', pt: 'Esaú correu ao seu encontro, abraçou-o, lançou-se ao seu pescoço e o beijou; e ambos choraram.' },
    { v: 5, en: 'And he lifted up his eyes, and saw the women and the children; and said, Who are those with thee? And he said, The children which God hath graciously given thy servant.', pt: 'Levantando os olhos, viu as mulheres e as crianças, e perguntou: Quem são esses que estão contigo? Jacó respondeu: São os filhos que Deus graciosamente deu ao teu servo.' },
    { v: 6, en: 'Then the handmaidens came near, they and their children, and they bowed themselves.', pt: 'Então as servas se aproximaram com seus filhos, e se inclinaram.' },
    { v: 7, en: 'And Leah also with her children came near, and bowed themselves: and after came Joseph near and Rachel, and they bowed themselves.', pt: 'Lia também se aproximou com seus filhos, e se inclinaram; depois José e Raquel se aproximaram e se inclinaram.' },
    { v: 8, en: 'And he said, What meanest thou by all this drove which I met? And he said, These are to find grace in the sight of my lord.', pt: 'Esaú perguntou: O que significa todo esse grupo que encontrei? Jacó respondeu: É para achar graça aos olhos do meu senhor.' },
    { v: 9, en: 'And Esau said, I have enough, my brother; keep that thou hast unto thyself.', pt: 'Esaú disse: Tenho de sobra, meu irmão; fique com o que é teu.' },
    { v: 10, en: 'And Jacob said, Nay, I pray thee, if now I have found grace in thy sight, then receive my present at my hand: for therefore I have seen thy face, as though I had seen the face of God, and thou wast pleased with me.', pt: 'Jacó respondeu: Não, por favor; se achei graça aos teus olhos, recebe o meu presente da minha mão; pois ver o teu rosto foi como ver o rosto de Deus, e tu me recebeste com agrado.' },
    { v: 11, en: 'Take, I pray thee, my blessing that is brought to thee; because God hath dealt graciously with me, and because I have enough. And he urged him, and he took it.', pt: 'Aceita, por favor, o meu presente que te foi trazido; porque Deus me tratou graciosamente e tenho de tudo. E Jacó insistiu, e Esaú o aceitou.' },
    { v: 12, en: 'And he said, Let us take our journey, and let us go, and I will go before thee.', pt: 'Esaú disse: Vamos partir e seguir o caminho, e eu irei adiante de ti.' },
    { v: 13, en: 'And he said unto him, My lord knoweth that the children are tender, and the flocks and herds with young are with me: and if men should overdrive them one day, all the flock will die.', pt: 'Jacó respondeu: Meu senhor sabe que as crianças são frágeis, e que tenho comigo ovelhas e vacas com crias; se as forçarem muito em um dia, todo o rebanho morrerá.' },
    { v: 14, en: 'Let my lord, I pray thee, pass over before his servant: and I will lead on softly, according as the cattle that goeth before me and the children be able to endure, until I come unto my lord unto Seir.', pt: 'Passe meu senhor adiante do seu servo; e eu seguirei devagar, de acordo com o passo do gado que vai à minha frente e das crianças, até que chegue ao meu senhor em Seir.' },
    { v: 15, en: 'And Esau said, Let me now leave with thee some of the folk that are with me. And he said, What needeth it? let me find grace in the sight of my lord.', pt: 'Esaú disse: Deixa-me ficar contigo parte do povo que está comigo. Jacó respondeu: Para que isso? Que eu ache graça aos olhos do meu senhor.' },
    { v: 16, en: 'So Esau returned that day on his way unto Seir.', pt: 'Assim Esaú voltou naquele dia pelo seu caminho a Seir.' },
    { v: 17, en: 'And Jacob journeyed to Succoth, and built him an house, and made booths for his cattle: therefore the name of the place is called Succoth.', pt: 'Jacó partiu para Sucote e construiu para si uma casa, e fez cabanas para o seu gado; por isso aquele lugar foi chamado Sucote.' },
    { v: 18, en: 'And Jacob came to Shalem, a city of Shechem, which is in the land of Canaan, when he came from Padanaram; and pitched his tent before the city.', pt: 'Depois Jacó chegou sãe e salvo à cidade de Siquém, na terra de Canaã, quando vinha da Padã-Arã; e armou a sua tenda defronte da cidade.' },
    { v: 19, en: 'And he bought a parcel of a field, where he had spread his tent, at the hand of the children of Hamor, Shechem\'s father, for an hundred pieces of money.', pt: 'Comprou uma porção do campo onde armara a sua tenda, dos filhos de Hamor, pai de Siquém, por cem peças de dinheiro.' },
    { v: 20, en: 'And he erected there an altar, and called it Elelohe-Israel.', pt: 'E ali levantou um altar e o chamou El-Eloé-Israel.' },
  ],
  34: [
    { v: 1, en: 'And Dinah the daughter of Leah, which she bare unto Jacob, went out to see the daughters of the land.', pt: 'Diná, filha que Lia dera a Jacó, saiu para ver as filhas da terra.' },
    { v: 2, en: 'And when Shechem the son of Hamor the Hivite, prince of the country, saw her, he took her, and lay with her, and defiled her.', pt: 'Quando Siquém, filho de Hamor, o heveu, príncipe daquela terra, a viu, tomou-a, deitou-se com ela e a violou.' },
    { v: 3, en: 'And his soul clave unto Dinah the daughter of Jacob, and he loved the damsel, and spake kindly unto the damsel.', pt: 'E a sua alma se apegou a Diná, filha de Jacó; ele amava a jovem e falava ao coração dela.' },
    { v: 4, en: 'And Shechem spake unto his father Hamor, saying, Get me this damsel to wife.', pt: 'Siquém falou com seu pai Hamor, dizendo: Toma-me esta jovem por mulher.' },
    { v: 5, en: 'And Jacob heard that he had defiled Dinah his daughter: now his sons were with his cattle in the field: and Jacob held his peace until they were come.', pt: 'Jacó ouviu que Siquém havia desonrado sua filha Diná; mas os seus filhos estavam no campo com o seu gado, e Jacó ficou calado até que eles voltassem.' },
    { v: 6, en: 'And Hamor the father of Shechem went out unto Jacob to commune with him.', pt: 'Hamor, pai de Siquém, saiu para falar com Jacó.' },
    { v: 7, en: 'And the sons of Jacob came out of the field when they heard it: and the men were grieved, and they were very wroth, because he had wrought folly in Israel in lying with Jacob\'s daughter; which thing ought not to be done.', pt: 'Os filhos de Jacó vieram do campo quando ouviram isso; e os homens ficaram magoados e muito irados, porque Siquém cometera uma ignomínia em Israel deitando-se com a filha de Jacó; o que não se devia fazer.' },
    { v: 8, en: 'And Hamor communed with them, saying, The soul of my son Shechem longeth for your daughter: I pray you give her him to wife.', pt: 'Hamor falou com eles, dizendo: O coração de meu filho Siquém deseja a vossa filha; dai-a a ele por mulher, por favor.' },
    { v: 9, en: 'And make ye marriages with us, and give your daughters unto us, and take our daughters unto you.', pt: 'Casai-vos conosco; dai as vossas filhas a nós, e tomai as nossas filhas para vós.' },
    { v: 10, en: 'And ye shall dwell with us: and the land shall be before you; dwell and trade ye therein, and get you possessions therein.', pt: 'Habitai conosco; e a terra estará diante de vós; habitai, negociai nela, e adquiri posses nela.' },
    { v: 11, en: 'And Shechem said unto her father and unto her brethren, Let me find grace in your eyes, and what ye shall say unto me I will give.', pt: 'Siquém disse ao pai e aos irmãos dela: Que eu ache graça aos vossos olhos, e o que me disserdes eu darei.' },
    { v: 12, en: 'Ask me never so much dowry and gift, and I will give according as ye shall say unto me: but give me the damsel to wife.', pt: 'Pedi-me muita dote e presente, e darei conforme me disserdes; mas dai-me a jovem por mulher.' },
    { v: 13, en: 'And the sons of Jacob answered Shechem and Hamor his father deceitfully, and said, because he had defiled Dinah their sister:', pt: 'Os filhos de Jacó responderam a Siquém e a Hamor, seu pai, com astúcia, por causa de que ele havia desonrado Diná, irmã deles,' },
    { v: 14, en: 'And they said unto them, We cannot do this thing, to give our sister to one that is uncircumcised; for that were a reproach unto us:', pt: 'e disseram-lhes: Não podemos fazer isso de dar nossa irmã a um homem incircunciso, pois isso seria uma desonra para nós.' },
    { v: 15, en: 'But in this will we consent unto you: If ye will be as we be, that every male of you be circumcised;', pt: 'Somente nisto consentiremos convosco: se vós fordes como nós, que todo homem entre vós seja circuncidado.' },
    { v: 16, en: 'Then will we give our daughters unto you, and we will take your daughters to us, and we will dwell with you, and we will become one people.', pt: 'Então daremos as nossas filhas a vós, e tomaremos as vossas filhas para nós, e habitaremos convosco, e nos tornaremos um único povo.' },
    { v: 17, en: 'But if ye will not hearken unto us, to be circumcised; then will we take our daughter, and we will be gone.', pt: 'Mas se não ouvirdes a nós, para serdes circuncidados, então tomaremos nossa filha e iremos embora.' },
    { v: 18, en: 'And their words pleased Hamor, and Shechem Hamor\'s son.', pt: 'As palavras agradaram a Hamor e a Siquém, filho de Hamor.' },
    { v: 19, en: 'And the young man deferred not to do the thing, because he had delight in Jacob\'s daughter: and he was more honourable than all the house of his father.', pt: 'O jovem não tardou em fazer isso, porque estava encantado com a filha de Jacó; e ele era o mais honrado de toda a casa de seu pai.' },
    { v: 20, en: 'And Hamor and Shechem his son came unto the gate of their city, and communed with the men of their city, saying,', pt: 'Hamor e Siquém, seu filho, foram à porta da sua cidade e falaram com os homens da sua cidade, dizendo:' },
    { v: 21, en: 'These men are peaceable with us; therefore let them dwell in the land, and trade therein; for the land, behold, it is large enough for them; let us take their daughters to us for wives, and let us give them our daughters.', pt: 'Esses homens são pacíficos conosco; que habitem na terra e negociem nela; pois a terra é ampla para eles; tomemos as suas filhas para nós por mulheres, e demos a eles as nossas filhas.' },
    { v: 22, en: 'Only herein will the men consent unto us for to dwell with us, to be one people, if every male among us be circumcised, as they are circumcised.', pt: 'Somente nisto os homens consentirão em habitar conosco para sermos um único povo: que todo homem entre nós seja circuncidado, como eles são circuncidados.' },
    { v: 23, en: 'Shall not their cattle and their substance and every beast of theirs be ours? only let us consent unto them, and they will dwell with us.', pt: 'O gado deles, os seus bens e todos os seus animais não serão nossos? Somente consintamos com eles, e habitarão conosco.' },
    { v: 24, en: 'And unto Hamor and unto Shechem his son hearkened all that went out of the gate of his city; and every male was circumcised, all that went out of the gate of his city.', pt: 'Hamor e Siquém, seu filho, foram ouvidos por todos que saíam da porta da sua cidade; e todo homem foi circuncidado, todos que saíam da porta da sua cidade.' },
    { v: 25, en: 'And it came to pass on the third day, when they were sore, that two of the sons of Jacob, Simeon and Levi, Dinah\'s brethren, took each man his sword, and came upon the city boldly, and slew all the males.', pt: 'Ao terceiro dia, quando estavam com dor, dois filhos de Jacó, Simeão e Levi, irmãos de Diná, tomaram cada um a sua espada, atacaram a cidade corajosamente e mataram todos os homens.' },
    { v: 26, en: 'And they slew Hamor and Shechem his son with the edge of the sword, and took Dinah out of Shechem\'s house, and went out.', pt: 'Mataram Hamor e Siquém, seu filho, ao fio da espada, e tomaram Diná da casa de Siquém e saíram.' },
    { v: 27, en: 'The sons of Jacob came upon the slain, and spoiled the city, because they had defiled their sister.', pt: 'Os filhos de Jacó vieram sobre os mortos e saquearam a cidade, porque haviam desonrado sua irmã.' },
    { v: 28, en: 'They took their sheep, and their oxen, and their asses, and that which was in the city, and that which was in the field,', pt: 'Tomaram as suas ovelhas, os seus bois, os seus jumentos, o que estava na cidade e o que estava no campo,' },
    { v: 29, en: 'And all their wealth, and all their little ones, and their wives took they captive, and spoiled even all that was in the house.', pt: 'e todas as suas riquezas; todas as suas crianças e as suas mulheres levaram cativas, e saquearam tudo o que havia nas casas.' },
    { v: 30, en: 'And Jacob said to Simeon and Levi, Ye have troubled me to make me to stink among the inhabitants of the land, among the Canaanites and the Perizzites: and I being few in number, they shall gather themselves together against me, and slay me; and I shall be destroyed, I and my house.', pt: 'Então Jacó disse a Simeão e Levi: Vós me perturbais, fazendo-me odioso entre os habitantes da terra, entre os cananeus e os ferezeus; e eu sou poucos em número, e eles se ajuntarão contra mim e me matarão; e serei destruído eu e minha casa.' },
    { v: 31, en: 'And they said, Should he deal with our sister as with an harlot?', pt: 'Eles responderam: Devia ele tratar a nossa irmã como a uma prostituta?' },
  ],
  35: [
    { v: 1, en: 'And God said unto Jacob, Arise, go up to Bethel, and dwell there: and make there an altar unto God, that appeared unto thee when thou fleddest from the face of Esau thy brother.', pt: 'Deus disse a Jacó: Levanta-te, sobe a Betel e habita ali; e faze ali um altar ao Deus que te apareceu quando fugias da face de Esaú, teu irmão.' },
    { v: 2, en: 'Then Jacob said unto his household, and to all that were with him, Put away the strange gods that are among you, and be clean, and change your garments:', pt: 'Então Jacó disse à sua família e a todos que estavam com ele: Tirai os deuses estranhos que estão entre vós, purificai-vos e mudai as vossas vestes.' },
    { v: 3, en: 'And let us arise, and go up to Bethel; and I will make there an altar unto God, who answered me in the day of my distress, and was with me in the way which I went.', pt: 'Levantemo-nos e subamos a Betel; e farei ali um altar ao Deus que me respondeu no dia da minha angústia e foi comigo no caminho que andei.' },
    { v: 4, en: 'And they gave unto Jacob all the strange gods which were in their hand, and all their earrings which were in their ears; and Jacob hid them under the oak which was by Shechem.', pt: 'Entregaram a Jacó todos os deuses estranhos que estavam nas suas mãos e os brincos que estavam nas suas orelhas; e Jacó os escondeu debaixo do carvalho que estava perto de Siquém.' },
    { v: 5, en: 'And they journeyed: and the terror of God was upon the cities that were round about them, and they did not pursue after the sons of Jacob.', pt: 'Partiram; e o terror de Deus estava sobre as cidades ao redor deles, e não perseguiram os filhos de Jacó.' },
    { v: 6, en: 'So Jacob came to Luz, which is in the land of Canaan, that is, Bethel, he and all the people that were with him.', pt: 'Assim Jacó chegou a Luz, que está na terra de Canaã, isto é, Betel, ele e todo o povo que estava com ele.' },
    { v: 7, en: 'And he built there an altar, and called the place Elbethel: because there God appeared unto him, when he fled from the face of his brother.', pt: 'E ali construiu um altar e chamou aquele lugar El-Betel, porque ali Deus lhe havia aparecido quando fugia da face de seu irmão.' },
    { v: 8, en: 'But Deborah Rebekah\'s nurse died, and she was buried beneath Bethel under an oak: and the name of it was called Allonbachuth.', pt: 'Mas Débora, ama de Rebeca, morreu, e foi sepultada abaixo de Betel, debaixo de um carvalho; por isso o chamaram Alon-Bacute.' },
    { v: 9, en: 'And God appeared unto Jacob again, when he came out of Padanaram, and blessed him.', pt: 'Deus apareceu a Jacó outra vez quando ele voltava da Padã-Arã, e o abençoou.' },
    { v: 10, en: 'And God said unto him, Thy name is Jacob: thy name shall not be called any more Jacob, but Israel shall be thy name: and he called his name Israel.', pt: 'E Deus lhe disse: O teu nome é Jacó; o teu nome não será mais chamado Jacó, mas Israel será o teu nome. E chamou o seu nome Israel.' },
    { v: 11, en: 'And God said unto him, I am God Almighty: be fruitful and multiply; a nation and a company of nations shall be of thee, and kings shall come out of thy loins;', pt: 'E Deus lhe disse: Eu sou o Deus Todo-Poderoso; sê fecundo e multiplica-te; uma nação e uma assembleia de nações procederão de ti, e reis sairão dos teus lombos.' },
    { v: 12, en: 'And the land which I gave Abraham and Isaac, to thee I will give it, and to thy seed after thee will I give the land.', pt: 'A terra que dei a Abraão e a Isaque, a ti a darei; e à tua descendência depois de ti darei a terra.' },
    { v: 13, en: 'And God went up from him in the place where he talked with him.', pt: 'E Deus subiu de junto dele no lugar onde havia falado com ele.' },
    { v: 14, en: 'And Jacob set up a pillar in the place where he talked with him, even a pillar of stone: and he poured a drink offering thereon, and he poured oil thereon.', pt: 'Jacó erigiu uma coluna no lugar onde havia falado com ele, uma coluna de pedra; e derramou sobre ela uma libação e derramou óleo sobre ela.' },
    { v: 15, en: 'And Jacob called the name of the place where God spake with him, Bethel.', pt: 'Jacó chamou Betel o nome do lugar onde Deus havia falado com ele.' },
    { v: 16, en: 'And they journeyed from Bethel; and there was but a little way to come to Ephrath: and Rachel travailed, and she had hard labour.', pt: 'Partiram de Betel; e havia ainda uma curta distância para chegar a Efrata, quando Raquel entrou em trabalho de parto, e teve um parto difícil.' },
    { v: 17, en: 'And it came to pass, when she was in hard labour, that the midwife said unto her, Fear not; thou shalt have this son also.', pt: 'Quando estava com dificuldade no parto, a parteira lhe disse: Não temas, pois também este é um filho para ti.' },
    { v: 18, en: 'And it came to pass, as her soul was in departing, (for she died) that she called his name Benoni: but his father called him Benjamin.', pt: 'Enquanto sua alma se ia — pois morreu — ela o chamou Benoni; mas seu pai o chamou Benjamim.' },
    { v: 19, en: 'And Rachel died, and was buried in the way to Ephrath, which is Bethlehem.', pt: 'Raquel morreu e foi sepultada no caminho para Efrata, que é Belém.' },
    { v: 20, en: 'And Jacob set a pillar upon her grave: that is the pillar of Rachel\'s grave unto this day.', pt: 'Jacó erigiu uma coluna sobre a sua sepultura; essa é a coluna da sepultura de Raquel até hoje.' },
    { v: 21, en: 'And Israel journeyed, and spread his tent beyond the tower of Edar.', pt: 'Israel partiu e armou a sua tenda além da torre de Eder.' },
    { v: 22, en: 'And it came to pass, when Israel dwelt in that land, that Reuben went and lay with Bilhah his father\'s concubine: and Israel heard it. Now the sons of Jacob were twelve:', pt: 'Quando Israel habitava naquela terra, Rúben foi e deitou-se com Bila, concubina de seu pai; e Israel ouviu isso. Ora, os filhos de Jacó eram doze.' },
    { v: 23, en: 'The sons of Leah; Reuben, Jacob\'s firstborn, and Simeon, and Levi, and Judah, and Issachar, and Zebulun:', pt: 'Os filhos de Lia: Rúben, o primogênito de Jacó, Simeão, Levi, Judá, Issacar e Zebulom.' },
    { v: 24, en: 'The sons of Rachel; Joseph, and Benjamin:', pt: 'Os filhos de Raquel: José e Benjamim.' },
    { v: 25, en: 'And the sons of Bilhah, Rachel\'s handmaid; Dan, and Naphtali:', pt: 'Os filhos de Bila, serva de Raquel: Dã e Naftali.' },
    { v: 26, en: 'And the sons of Zilpah, Leah\'s handmaid; Gad, and Asher: these are the sons of Jacob, which were born to him in Padanaram.', pt: 'Os filhos de Zilpa, serva de Lia: Gade e Aser. Estes são os filhos de Jacó que lhe nasceram na Padã-Arã.' },
    { v: 27, en: 'And Jacob came unto Isaac his father unto Mamre, unto the city of Arbah, which is Hebron, where Abraham and Isaac sojourned.', pt: 'Jacó chegou a Isaque, seu pai, a Manre, à cidade de Arba, que é Hebrom, onde Abraão e Isaque tinham peregrinado.' },
    { v: 28, en: 'And the days of Isaac were an hundred and fourscore years.', pt: 'Os dias de Isaque foram cento e oitenta anos.' },
    { v: 29, en: 'And Isaac gave up the ghost, and died, and was gathered unto his people, being old and full of days: and his sons Esau and Jacob buried him.', pt: 'E Isaque expirou e morreu, e foi reunido ao seu povo, velho e cheio de dias; e seus filhos Esaú e Jacó o sepultaram.' },
  ],
  36: [
    { v: 1, en: 'Now these are the generations of Esau, who is Edom.', pt: 'Estas são as gerações de Esaú, que é Edom.' },
    { v: 2, en: 'Esau took his wives of the daughters of Canaan; Adah the daughter of Elon the Hittite, and Aholibamah the daughter of Anah the daughter of Zibeon the Hivite;', pt: 'Esaú tomou as suas mulheres das filhas de Canaã: Ada, filha de Elom, o heteu; e Oolibama, filha de Aná, filha de Zibeão, o heveu.' },
    { v: 3, en: 'And Bashemath Ishmael\'s daughter, sister of Nebajoth.', pt: 'E Basemate, filha de Ismael, irmã de Nebaiote.' },
    { v: 4, en: 'And Adah bare to Esau Eliphaz; and Bashemath bare Reuel;', pt: 'Ada deu a Esaú Elifaz; e Basemate deu à luz Reuel.' },
    { v: 5, en: 'And Aholibamah bare Jeush, and Jaalam, and Korah: these are the sons of Esau, which were born unto him in the land of Canaan.', pt: 'E Oolibama deu à luz Jeús, Jalão e Coré; estes são os filhos de Esaú que lhe nasceram na terra de Canaã.' },
    { v: 6, en: 'And Esau took his wives, and his sons, and his daughters, and all the persons of his house, and his cattle, and all his beasts, and all his substance, which he had got in the land of Canaan; and went into the country from the face of his brother Jacob.', pt: 'Esaú tomou suas mulheres, seus filhos, suas filhas e todas as pessoas da sua casa, seu gado, todos os seus animais e todos os seus bens que havia adquirido na terra de Canaã, e foi para outro país, longe de Jacó, seu irmão.' },
    { v: 7, en: 'For their riches were more than that they might dwell together; and the land wherein they were strangers could not bear them because of their cattle.', pt: 'Pois as riquezas deles eram mais do que permitia habitar juntos; e a terra em que peregrinavam não podia sustentá-los por causa do seu gado.' },
    { v: 8, en: 'Thus dwelt Esau in mount Seir: Esau is Edom.', pt: 'Assim habitou Esaú no monte Seir; Esaú é Edom.' },
    { v: 9, en: 'And these are the generations of Esau the father of the Edomites in mount Seir:', pt: 'Estas são as gerações de Esaú, pai dos edomitas, no monte Seir.' },
    { v: 10, en: 'These are the names of Esau\'s sons; Eliphaz the son of Adah the wife of Esau, Reuel the son of Bashemath the wife of Esau.', pt: 'Estes são os nomes dos filhos de Esaú: Elifaz, filho de Ada, mulher de Esaú; Reuel, filho de Basemate, mulher de Esaú.' },
    { v: 11, en: 'And the sons of Eliphaz were Teman, Omar, Zepho, and Gatam, and Kenaz.', pt: 'Os filhos de Elifaz foram Temã, Omar, Zefo, Gatão e Quenaz.' },
    { v: 12, en: 'And Timna was concubine to Eliphaz Esau\'s son; and she bare to Eliphaz Amalek: these were the sons of Adah Esau\'s wife.', pt: 'Timna era concubina de Elifaz, filho de Esaú; e ela deu a Elifaz Amaleque. Estes foram os filhos de Ada, mulher de Esaú.' },
    { v: 13, en: 'And these are the sons of Reuel; Nahath, and Zerah, Shammah, and Mizzah: these were the sons of Bashemath Esau\'s wife.', pt: 'Estes são os filhos de Reuel: Naate, Zerá, Samá e Mizá; estes foram os filhos de Basemate, mulher de Esaú.' },
    { v: 14, en: 'And these were the sons of Aholibamah, the daughter of Anah the daughter of Zibeon, Esau\'s wife: and she bare to Esau Jeush, and Jaalam, and Korah.', pt: 'Estes foram os filhos de Oolibama, filha de Aná, filha de Zibeão, mulher de Esaú; ela deu a Esaú Jeús, Jalão e Coré.' },
    { v: 15, en: 'These were dukes of the sons of Esau: the sons of Eliphaz the firstborn son of Esau; duke Teman, duke Omar, duke Zepho, duke Kenaz,', pt: 'Estes foram os chefes dos filhos de Esaú; os filhos de Elifaz, primogênito de Esaú: chefe Temã, chefe Omar, chefe Zefo, chefe Quenaz,' },
    { v: 16, en: 'Duke Korah, duke Gatam, and duke Amalek: these are the dukes that came of Eliphaz in the land of Edom; these were the sons of Adah.', pt: 'chefe Coré, chefe Gatão e chefe Amaleque; estes são os chefes que saíram de Elifaz na terra de Edom; estes foram os filhos de Ada.' },
    { v: 17, en: 'And these are the sons of Reuel Esau\'s son; duke Nahath, duke Zerah, duke Shammah, duke Mizzah: these are the dukes that came of Reuel in the land of Edom; these are the sons of Bashemath Esau\'s wife.', pt: 'Estes são os filhos de Reuel, filho de Esaú: chefe Naate, chefe Zerá, chefe Samá, chefe Mizá; estes são os chefes que saíram de Reuel na terra de Edom; estes são os filhos de Basemate, mulher de Esaú.' },
    { v: 18, en: 'And these are the sons of Aholibamah Esau\'s wife; duke Jeush, duke Jaalam, duke Korah: these were the dukes that came of Aholibamah the daughter of Anah, Esau\'s wife.', pt: 'Estes são os filhos de Oolibama, mulher de Esaú: chefe Jeús, chefe Jalão, chefe Coré; estes foram os chefes que saíram de Oolibama, filha de Aná, mulher de Esaú.' },
    { v: 19, en: 'These are the sons of Esau, who is Edom, and these are their dukes.', pt: 'Estes são os filhos de Esaú, que é Edom, e estes são os seus chefes.' },
    { v: 20, en: 'These are the sons of Seir the Horite, who inhabited the land; Lotan, and Shobal, and Zibeon, and Anah,', pt: 'Estes são os filhos de Seir, o horeu, habitantes daquela terra: Lotã, Sobal, Zibeão e Aná,' },
    { v: 21, en: 'And Dishon, and Ezer, and Dishan: these are the dukes of the Horites, the children of Seir in the land of Edom.', pt: 'Disom, Ezer e Disã; estes são os chefes dos horeus, filhos de Seir, na terra de Edom.' },
    { v: 22, en: 'And the children of Lotan were Hori and Hemam; and Lotan\'s sister was Timna.', pt: 'Os filhos de Lotã foram Hori e Hemã; e a irmã de Lotã foi Timna.' },
    { v: 23, en: 'And the children of Shobal were these; Alvan, and Manahath, and Ebal, Shepho, and Onam.', pt: 'Os filhos de Sobal foram: Alvã, Manaate, Ebal, Sefo e Onã.' },
    { v: 24, en: 'And these are the children of Zibeon; both Ajah, and Anah: this was that Anah that found the mules in the wilderness, as he fed the asses of Zibeon his father.', pt: 'Estes são os filhos de Zibeão: Aia e Aná; este Aná foi quem achou as fontes de água quente no deserto quando apascentava os jumentos de Zibeão, seu pai.' },
    { v: 25, en: 'And the children of Anah were these; Dishon, and Aholibamah the daughter of Anah.', pt: 'Os filhos de Aná foram: Disom e Oolibama, filha de Aná.' },
    { v: 26, en: 'And these are the children of Dishon; Hemdan, and Eshban, and Ithran, and Cheran.', pt: 'Estes são os filhos de Disom: Hemdã, Esbã, Itrã e Querã.' },
    { v: 27, en: 'The children of Ezer are these; Bilhan, and Zaavan, and Akan.', pt: 'Os filhos de Ezer são estes: Bilã, Zaavã e Acã.' },
    { v: 28, en: 'The children of Dishan are these; Uz, and Aran.', pt: 'Os filhos de Disã são: Uz e Arã.' },
    { v: 29, en: 'These are the dukes that came of the Horites; duke Lotan, duke Shobal, duke Zibeon, duke Anah,', pt: 'Estes são os chefes que saíram dos horeus: chefe Lotã, chefe Sobal, chefe Zibeão, chefe Aná,' },
    { v: 30, en: 'Duke Dishon, duke Ezer, duke Dishan: these are the dukes that came of Hori, among their dukes in the land of Seir.', pt: 'chefe Disom, chefe Ezer, chefe Disã; estes são os chefes que saíram de Hori, entre os seus chefes na terra de Seir.' },
    { v: 31, en: 'And these are the kings that reigned in the land of Edom, before there reigned any king over the children of Israel.', pt: 'Estes são os reis que reinaram na terra de Edom, antes de reinar rei sobre os filhos de Israel.' },
    { v: 32, en: 'And Bela the son of Beor reigned in Edom: and the name of his city was Dinhabah.', pt: 'Bela, filho de Beor, reinou em Edom; o nome da sua cidade era Dinabá.' },
    { v: 33, en: 'And Bela died, and Jobab the son of Zerah of Bozrah reigned in his stead.', pt: 'Bela morreu, e Jobabe, filho de Zerá, de Bozra, reinou em seu lugar.' },
    { v: 34, en: 'And Jobab died, and Husham of the land of Temani reigned in his stead.', pt: 'Jobabe morreu, e Husã, da terra dos temanitas, reinou em seu lugar.' },
    { v: 35, en: 'And Husham died, and Hadad the son of Bedad, who smote Midian in the field of Moab, reigned in his stead: and the name of his city was Avith.', pt: 'Husã morreu, e Hadade, filho de Bedad, que feriu Midiã no campo de Moabe, reinou em seu lugar; o nome da sua cidade era Avite.' },
    { v: 36, en: 'And Hadad died, and Samlah of Masrekah reigned in his stead.', pt: 'Hadade morreu, e Samla, de Masreca, reinou em seu lugar.' },
    { v: 37, en: 'And Samlah died, and Saul of Rehoboth by the river reigned in his stead.', pt: 'Samla morreu, e Saul, de Reobote junto ao rio, reinou em seu lugar.' },
    { v: 38, en: 'And Saul died, and Baalhanan the son of Achbor reigned in his stead.', pt: 'Saul morreu, e Baal-Hanã, filho de Acbor, reinou em seu lugar.' },
    { v: 39, en: 'And Baalhanan the son of Achbor died, and Hadar reigned in his stead: and the name of his city was Pau; and his wife\'s name was Mehetabel, the daughter of Matred, the daughter of Mezahab.', pt: 'Baal-Hanã, filho de Acbor, morreu, e Hadade reinou em seu lugar; o nome da sua cidade era Pau; e o nome de sua mulher era Meetabel, filha de Matrede, filha de Me-Zaabe.' },
    { v: 40, en: 'And these are the names of the dukes that came of Esau, according to their families, after their places, by their names; duke Timnah, duke Alvah, duke Jetheth,', pt: 'Estes são os nomes dos chefes que saíram de Esaú, segundo as suas famílias, segundo os seus lugares, pelos seus nomes: chefe Timna, chefe Alva, chefe Jetete,' },
    { v: 41, en: 'Duke Aholibamah, duke Elah, duke Pinon,', pt: 'chefe Oolibama, chefe Elá, chefe Pinão,' },
    { v: 42, en: 'Duke Kenaz, duke Teman, duke Mibzar,', pt: 'chefe Quenaz, chefe Temã, chefe Mibzar,' },
    { v: 43, en: 'Duke Magdiel, duke Iram: these be the dukes of Edom, according to their habitations in the land of their possession: he is Esau the father of the Edomites.', pt: 'chefe Magdiel, chefe Irã; estes são os chefes de Edom, segundo as suas habitações na terra da sua possessão; este é Esaú, pai dos edomitas.' },
  ],
  37: [
    { v: 1, en: 'And Jacob dwelt in the land wherein his father was a stranger, in the land of Canaan.', pt: 'Jacó habitou na terra em que seu pai havia peregrinado, na terra de Canaã.' },
    { v: 2, en: 'These are the generations of Jacob. Joseph, being seventeen years old, was feeding the flock with his brethren; and the lad was with the sons of Bilhah, and with the sons of Zilpah, his father\'s wives: and Joseph brought unto his father their evil report.', pt: 'Estas são as gerações de Jacó. José, com dezessete anos, apascentava o rebanho com seus irmãos; e o jovem estava com os filhos de Bila e com os filhos de Zilpa, mulheres de seu pai; e José levou ao seu pai o mau relatório deles.' },
    { v: 3, en: 'Now Israel loved Joseph more than all his children, because he was the son of his old age: and he made him a coat of many colours.', pt: 'Israel amava a José mais do que a todos os seus filhos, porque era filho da sua velhice; e fez-lhe uma túnica de várias cores.' },
    { v: 4, en: 'And when his brethren saw that their father loved him more than all his brethren, they hated him, and could not speak peaceably unto him.', pt: 'Quando seus irmãos viram que seu pai o amava mais do que a todos os irmãos, odiaram-no e não podiam falar-lhe pacificamente.' },
    { v: 5, en: 'And Joseph dreamed a dream, and he told it his brethren: and they hated him yet the more.', pt: 'José teve um sonho e o contou a seus irmãos; e eles o odiaram ainda mais.' },
    { v: 6, en: 'And he said unto them, Hear, I pray you, this dream which I have dreamed:', pt: 'Disse-lhes: Ouvi, por favor, este sonho que tive.' },
    { v: 7, en: 'For, behold, we were binding sheaves in the field, and, lo, my sheaf arose, and also stood upright; and, behold, your sheaves stood round about, and made obeisance to my sheaf.', pt: 'Estávamos atando feixes no campo; e eis que o meu feixe se levantou e ficou de pé; e os vossos feixes estavam ao redor e se inclinavam para o meu feixe.' },
    { v: 8, en: 'And his brethren said to him, Shalt thou indeed reign over us? or shalt thou indeed have dominion over us? And they hated him yet the more for his dreams, and for his words.', pt: 'Seus irmãos lhe disseram: Reinarás mesmo sobre nós? ou dominarás sobre nós? E o odiaram ainda mais por causa dos seus sonhos e das suas palavras.' },
    { v: 9, en: 'And he dreamed yet another dream, and told it his brethren, and said, Behold, I have dreamed a dream more; and, behold, the sun and the moon and the eleven stars made obeisance to me.', pt: 'Teve ainda outro sonho e o contou a seus irmãos, dizendo: Tive mais um sonho; e eis que o sol, a lua e onze estrelas se inclinavam para mim.' },
    { v: 10, en: 'And he told it to his father, and to his brethren: and his father rebuked him, and said unto him, What is this dream that thou hast dreamed? Shall I and thy mother and thy brethren indeed come to bow down ourselves to thee to the earth?', pt: 'Contou-o a seu pai e a seus irmãos; e seu pai o repreendeu e lhe disse: Que sonho é este que tiveste? Viremos eu, tua mãe e teus irmãos nos inclinar perante ti até ao chão?' },
    { v: 11, en: 'And his brethren envied him; but his father observed the saying.', pt: 'Seus irmãos tiveram inveja dele; mas seu pai guardou a palavra no coração.' },
    { v: 12, en: 'And his brethren went to feed their father\'s flock in Shechem.', pt: 'Seus irmãos foram apascentar o rebanho de seu pai em Siquém.' },
    { v: 13, en: 'And Israel said unto Joseph, Do not thy brethren feed the flock in Shechem? come, and I will send thee unto them. And he said to him, Here am I.', pt: 'Israel disse a José: Não estão teus irmãos apascentando o rebanho em Siquém? Vem, enviar-te-ei a eles. E ele lhe disse: Eis-me aqui.' },
    { v: 14, en: 'And he said to him, Go, I pray thee, see whether it be well with thy brethren, and well with the flocks; and bring me word again. So he sent him out of the vale of Hebron, and he came to Shechem.', pt: 'Disse-lhe: Vai, por favor, ver se teus irmãos estão bem e se o rebanho está bem; e traz-me notícias. Enviou-o do vale de Hebrom, e ele foi a Siquém.' },
    { v: 15, en: 'And a certain man found him, and, behold, he was wandering in the field: and the man asked him, saying, What seekest thou?', pt: 'Um homem o encontrou vagando pelo campo, e o homem lhe perguntou: O que procuras?' },
    { v: 16, en: 'And he said, I seek my brethren: tell me, I pray thee, where they feed their flocks.', pt: 'Respondeu: Procuro meus irmãos; dize-me, por favor, onde apascentam os rebanhos.' },
    { v: 17, en: 'And the man said, They are departed hence; for I heard them say, Let us go to Dothan. And Joseph went after his brethren, and found them in Dothan.', pt: 'O homem disse: Partiram daqui; pois os ouvi dizer: Vamos a Dotã. José foi atrás de seus irmãos e os achou em Dotã.' },
    { v: 18, en: 'And when they saw him afar off, even before he came near unto them, they conspired against him to slay him.', pt: 'Quando o viram de longe, antes que chegasse perto deles, conspiraram contra ele para o matar.' },
    { v: 19, en: 'And they said one to another, Behold, this dreamer cometh.', pt: 'Disseram uns aos outros: Eis que vem o sonhador.' },
    { v: 20, en: 'Come now therefore, and let us slay him, and cast him into some pit, and we will say, Some evil beast hath devoured him: and we shall see what will become of his dreams.', pt: 'Vinde pois, e matemo-lo, e lancemo-lo em uma das cisternas; e diremos que um animal mau o devorou; e veremos o que acontecerá com os seus sonhos.' },
    { v: 21, en: 'And Reuben heard it, and he delivered him out of their hands; and said, Let us not kill him.', pt: 'Rúben ouviu isso e o livrou das suas mãos, dizendo: Não o matemos.' },
    { v: 22, en: 'And Reuben said unto them, Shed no blood, but cast him into this pit that is in the wilderness, and lay no hand upon him; that he might rid him out of their hands, to deliver him to his father again.', pt: 'Rúben lhes disse: Não derrameis sangue; lançai-o nesta cisterna que está no deserto, e não pouseis a mão sobre ele; para que o livrasse das suas mãos e o devolvesse a seu pai.' },
    { v: 23, en: 'And it came to pass, when Joseph was come unto his brethren, that they stript Joseph out of his coat, his coat of many colours that was on him;', pt: 'Quando José chegou a seus irmãos, eles tiraram de José a sua túnica, a túnica de várias cores que trazia,' },
    { v: 24, en: 'And they took him, and cast him into a pit: and the pit was empty, there was no water in it.', pt: 'e o tomaram e o lançaram na cisterna; a cisterna estava vazia, sem água.' },
    { v: 25, en: 'And they sat down to eat bread: and they lifted up their eyes and looked, and, behold, a company of Ishmeelites came from Gilead with their camels bearing spicery and balm and myrrh, going to carry it down to Egypt.', pt: 'Sentaram-se para comer pão; e levantando os olhos, viram uma caravana de ismaelitas que vinha de Gileade, com os seus camelos carregando especiarias, bálsamo e mirra, e que ia levá-las ao Egito.' },
    { v: 26, en: 'And Judah said unto his brethren, What profit is it if we slay our brother, and conceal his blood?', pt: 'Judá disse a seus irmãos: Que proveito há se matarmos nosso irmão e encobrirmos o seu sangue?' },
    { v: 27, en: 'Come, and let us sell him to the Ishmeelites, and let not our hand be upon him; for he is our brother and our flesh: and his brethren were content.', pt: 'Vinde, vendamo-lo aos ismaelitas, e não ponhamos a nossa mão sobre ele; pois ele é nosso irmão e nossa carne. E seus irmãos concordaram.' },
    { v: 28, en: 'Then there passed by Midianites merchantmen; and they drew and lifted up Joseph out of the pit, and sold Joseph to the Ishmeelites for twenty pieces of silver: and they brought Joseph into Egypt.', pt: 'Passaram mercadores midianitas; e eles puxaram e tiraram José da cisterna, e venderam José aos ismaelitas por vinte peças de prata; e eles trouxeram José ao Egito.' },
    { v: 29, en: 'And Reuben returned unto the pit; and, behold, Joseph was not in the pit; and he rent his clothes.', pt: 'Rúben voltou à cisterna e, eis que José não estava na cisterna; e rasgou as suas vestes.' },
    { v: 30, en: 'And he returned unto his brethren, and said, The child is not; and I, whither shall I go?', pt: 'Voltou a seus irmãos e disse: O menino não está; e eu, para onde irei?' },
    { v: 31, en: 'And they took Joseph\'s coat, and killed a kid of the goats, and dipped the coat in the blood;', pt: 'Tomaram a túnica de José, mataram um bode e mergulharam a túnica no sangue.' },
    { v: 32, en: 'And they sent the coat of many colours, and they brought it to their father; and said, This have we found: know now whether it be thy son\'s coat or no.', pt: 'Enviaram a túnica de várias cores e a trouxeram ao seu pai, dizendo: Isto achamos; reconhece agora se é ou não a túnica do teu filho.' },
    { v: 33, en: 'And he knew it, and said, It is my son\'s coat; an evil beast hath devoured him; Joseph is without doubt rent in pieces.', pt: 'Ele a reconheceu e disse: É a túnica do meu filho; um animal mau o devorou; José foi certamente despedaçado.' },
    { v: 34, en: 'And Jacob rent his clothes, and put sackcloth upon his loins, and mourned for his son many days.', pt: 'Jacó rasgou as suas vestes, pôs pano de saco nos seus lombos e pranteou seu filho muitos dias.' },
    { v: 35, en: 'And all his sons and all his daughters rose up to comfort him; but he refused to be comforted; and he said, For I will go down into the grave unto my son mourning. Thus his father wept for him.', pt: 'Todos os seus filhos e todas as suas filhas se levantaram para consolá-lo; mas ele recusou ser consolado, dizendo: Descerei ao sepulcro pranteando meu filho. Assim seu pai chorou por ele.' },
    { v: 36, en: 'And the Midianites sold him into Egypt unto Potiphar, an officer of Pharaoh\'s, and captain of the guard.', pt: 'Os midianitas o venderam no Egito a Potifar, oficial do faraó e capitão da guarda.' },
  ],
  38: [
    { v: 1, en: 'And it came to pass at that time, that Judah went down from his brethren, and turned in to a certain Adullamite, whose name was Hirah.', pt: 'Naquele tempo aconteceu que Judá desceu de junto de seus irmãos e se desviou para um adulamita cujo nome era Hirá.' },
    { v: 2, en: 'And Judah saw there a daughter of a certain Canaanite, whose name was Shuah; and he took her, and went in unto her.', pt: 'Judá viu ali a filha de um cananeu cujo nome era Sua; e ele a tomou e se uniu a ela.' },
    { v: 3, en: 'And she conceived, and bare a son; and he called his name Er.', pt: 'Ela concebeu e deu à luz um filho; e ele o chamou Er.' },
    { v: 4, en: 'And she conceived again, and bare a son; and she called his name Onan.', pt: 'Concebeu outra vez e deu à luz um filho; e ela o chamou Onã.' },
    { v: 5, en: 'And she yet again conceived, and bare a son; and called his name Shelah: and he was at Chezib, when she bare him.', pt: 'E ela novamente concebeu e deu à luz um filho; e chamou-o Selá; e Judá estava em Quezibe quando ela o deu à luz.' },
    { v: 6, en: 'And Judah took a wife for Er his firstborn, whose name was Tamar.', pt: 'Judá tomou para Er, seu primogênito, uma mulher cujo nome era Tamar.' },
    { v: 7, en: 'And Er, Judah\'s firstborn, was wicked in the sight of the LORD; and the LORD slew him.', pt: 'Er, primogênito de Judá, era mau aos olhos do Senhor; e o Senhor o feriu de morte.' },
    { v: 8, en: 'And Judah said unto Onan, Go in unto thy brother\'s wife, and marry her, and raise up seed to thy brother.', pt: 'Judá disse a Onã: Une-te à mulher do teu irmão, casa com ela, e levanta descendência ao teu irmão.' },
    { v: 9, en: 'And Onan knew that the seed should not be his; and it came to pass, when he went in unto his brother\'s wife, that he spilled it on the ground, lest that he should give seed to his brother.', pt: 'Onã sabia que a descendência não seria sua; e quando se unia à mulher do seu irmão, derramava no chão, para não dar descendência ao seu irmão.' },
    { v: 10, en: 'And the thing which he did displeased the LORD: wherefore he slew him also.', pt: 'O que ele fez desagradou ao Senhor; por isso o feriu de morte também.' },
    { v: 11, en: 'Then said Judah to Tamar his daughter in law, Remain a widow at thy father\'s house, till Shelah my son be grown: for he said, Lest peradventure he die also, as his brethren did. And Tamar went and dwelt in her father\'s house.', pt: 'Então Judá disse a Tamar, sua nora: Fica viúva em casa de teu pai até que Selá, meu filho, cresça; pois ele pensava: Que ele não morra também, como seus irmãos. E Tamar foi e ficou em casa de seu pai.' },
    { v: 12, en: 'And in process of time the daughter of Shuah Judah\'s wife died; and Judah was comforted, and went up unto his sheepshearers to Timnath, he and his friend Hirah the Adullamite.', pt: 'Com o passar do tempo, a filha de Sua, mulher de Judá, morreu; e Judá foi consolado, e subiu a Timna, aos seus tosquiadores de ovelhas, ele e seu amigo Hirá, o adulamita.' },
    { v: 13, en: 'And it was told Tamar, saying, Behold thy father in law goeth up to Timnath to shear his sheep.', pt: 'Foi dito a Tamar: Eis que teu sogro sobe a Timna para tosquiar as suas ovelhas.' },
    { v: 14, en: 'And she put her widow\'s garments off from her, and covered her with a vail, and wrapped herself, and sat in an open place, which is by the way to Timnath; for she saw that Shelah was grown, and she was not given unto him to wife.', pt: 'Ela tirou as suas vestes de viuvez, cobriu-se com um véu e se envolveu nele, e sentou-se à entrada de Enaim, que está no caminho de Timna; pois via que Selá havia crescido, mas ela não lhe havia sido dada por mulher.' },
    { v: 15, en: 'When Judah saw her, he thought her to be an harlot; because she had covered her face.', pt: 'Quando Judá a viu, pensou que ela fosse prostituta, porque havia coberto o rosto.' },
    { v: 16, en: 'And he turned unto her by the way, and said, Go to, I pray thee, let me come in unto thee; (for he knew not that she was his daughter in law.) And she said, What wilt thou give me, that thou mayest come in unto me?', pt: 'Ele se desviou para ela pelo caminho e disse: Deixa-me, por favor, me aproximar de ti; pois não sabia que era sua nora. Ela disse: O que me darás para te aproximares de mim?' },
    { v: 17, en: 'And he said, I will send thee a kid from the flock. And she said, Wilt thou give me a pledge, till thou send it?', pt: 'Ele disse: Enviar-te-ei um cabrito do rebanho. Ela disse: Darás um penhor até o enviares?' },
    { v: 18, en: 'And he said, What pledge shall I give thee? And she said, Thy signet, and thy bracelets, and thy staff that is in thine hand. And he gave it her, and came in unto her, and she conceived by him.', pt: 'Ele perguntou: Que penhor te darei? Ela respondeu: O teu sinete, o teu cordão e o teu cajado que está em tua mão. Ele os deu a ela e se uniu a ela, e ela concebeu por ele.' },
    { v: 19, en: 'And she arose, and went away, and laid by her vail from her, and put on the garments of her widowhood.', pt: 'Ela se levantou, foi embora, tirou o seu véu e vestiu as suas vestes de viuvez.' },
    { v: 20, en: 'And Judah sent the kid by the hand of his friend the Adullamite, to receive his pledge from the woman\'s hand: but he found her not.', pt: 'Judá enviou o cabrito pela mão do seu amigo o adulamita, para receber o penhor da mão da mulher; mas ele não a achou.' },
    { v: 21, en: 'Then he asked the men of that place, saying, Where is the harlot, that was openly by the way side? And they said, There was no harlot in this place.', pt: 'Perguntou aos homens daquele lugar: Onde está a prostituta que estava à beira do caminho? E eles disseram: Não houve prostituta aqui.' },
    { v: 22, en: 'And he returned to Judah, and said, I cannot find her; and also the men of the place said, that there was no harlot in this place.', pt: 'Voltou a Judá e disse: Não a achei; e também os homens do lugar disseram: Não houve prostituta aqui.' },
    { v: 23, en: 'And Judah said, Let her take it to her, lest we be shamed: behold, I sent this kid, and thou hast not found her.', pt: 'Judá disse: Que fique com isso, para que não sejamos envergonhados; eis que enviei esse cabrito, e tu não a achaste.' },
    { v: 24, en: 'And it came to pass about three months after, that it was told Judah, saying, Tamar thy daughter in law hath played the harlot; and also, behold, she is with child by whoredom. And Judah said, Bring her forth, and let her be burnt.', pt: 'Cerca de três meses depois, foi dito a Judá: Tamar, tua nora, se prostituiu; e eis que ela está grávida pela prostituição. Judá disse: Tirai-a para fora e que seja queimada.' },
    { v: 25, en: 'When she was brought forth, she sent to her father in law, saying, By the man, whose these are, am I with child: and she said, Discern, I pray thee, whose are these, the signet, and bracelets, and staff.', pt: 'Quando a trouxeram, ela mandou dizer a seu sogro: Estou grávida do homem a quem pertencem estas coisas; e disse: Reconhece, por favor, de quem são este sinete, este cordão e este cajado.' },
    { v: 26, en: 'And Judah acknowledged them, and said, She hath been more righteous than I; because that I gave her not to Shelah my son. And he knew her again no more.', pt: 'Judá os reconheceu e disse: Ela é mais justa do que eu, porque não a dei a Selá, meu filho. E nunca mais se uniu a ela.' },
    { v: 27, en: 'And it came to pass in the time of her travail, that, behold, twins were in her womb.', pt: 'E ao tempo do parto, eis que havia gêmeos no seu ventre.' },
    { v: 28, en: 'And it came to pass, when she travailed, that the one put out his hand: and the midwife took and bound upon his hand a scarlet thread, saying, This came out first.', pt: 'Quando ela dava à luz, um deles pôs a mão para fora; a parteira tomou-a e atou um fio escarlate na sua mão, dizendo: Este saiu primeiro.' },
    { v: 29, en: 'And it came to pass, as he drew back his hand, that, behold, his brother came out: and she said, How hast thou broken forth? this breach be upon thee: therefore his name was called Pharez.', pt: 'Mas quando ele retirou a sua mão, eis que saiu o seu irmão; e ela disse: Como te abriste passagem? Esta abertura seja sobre ti; por isso o seu nome foi chamado Fares.' },
    { v: 30, en: 'And afterward came out his brother, that had the scarlet thread upon his hand: and his name was called Zarah.', pt: 'Depois saiu o seu irmão que tinha o fio escarlate na mão; e o seu nome foi chamado Zerá.' },
  ],
  39: [
    { v: 1, en: 'And Joseph was brought down to Egypt; and Potiphar, an officer of Pharaoh, captain of the guard, an Egyptian, bought him of the hands of the Ishmeelites, which had brought him down thither.', pt: 'José foi levado ao Egito; e Potifar, oficial do faraó, capitão da guarda, um egípcio, o comprou da mão dos ismaelitas que o haviam trazido para lá.' },
    { v: 2, en: 'And the LORD was with Joseph, and he was a prosperous man; and he was in the house of his master the Egyptian.', pt: 'O Senhor estava com José, e ele prosperava; estava na casa do seu senhor, o egípcio.' },
    { v: 3, en: 'And his master saw that the LORD was with him, and that the LORD made all that he did to prosper in his hand.', pt: 'Seu senhor viu que o Senhor estava com ele e que o Senhor fazia prosperar tudo o que ele fazia.' },
    { v: 4, en: 'And Joseph found grace in his sight, and he served him: and he made him overseer over his house, and all that he had he put into his hand.', pt: 'José achou graça aos seus olhos e o servia; e ele o fez mordomo sobre a sua casa, e tudo o que tinha pôs em suas mãos.' },
    { v: 5, en: 'And it came to pass from the time that he had made him overseer in his house, and over all that he had, that the LORD blessed the Egyptian\'s house for Joseph\'s sake; and the blessing of the LORD was upon all that he had in the house, and in the field.', pt: 'E desde que o fez mordomo sobre a sua casa e sobre tudo o que tinha, o Senhor abençoou a casa do egípcio por causa de José; e a bênção do Senhor estava sobre tudo o que ele tinha na casa e no campo.' },
    { v: 6, en: 'And he left all that he had in Joseph\'s hand; and he knew not ought he had, save the bread which he did eat. And Joseph was a goodly person, and well favoured.', pt: 'Ele deixou tudo o que tinha nas mãos de José; e não se preocupava com nada do que tinha, exceto com o pão que comia. E José era belo de aparência e formoso.' },
    { v: 7, en: 'And it came to pass after these things, that his master\'s wife cast her eyes upon Joseph; and she said, Lie with me.', pt: 'Depois dessas coisas, a mulher de seu senhor pôs os olhos em José e disse: Deita-te comigo.' },
    { v: 8, en: 'But he refused, and said unto his master\'s wife, Behold, my master wotteth not what is with me in the house, and he hath committed all that he hath to my hand;', pt: 'Mas ele recusou, e disse à mulher de seu senhor: Eis que meu senhor não sabe o que há comigo na casa, e tudo o que tem, entregou em minhas mãos.' },
    { v: 9, en: 'There is none greater in this house than I; neither hath he kept back any thing from me but thee, because thou art his wife: how then can I do this great wickedness, and sin against God?', pt: 'Não há ninguém maior nesta casa do que eu; nem me reteve nada, exceto tu, porque és sua mulher; como, então, faria este grande mal e pecaria contra Deus?' },
    { v: 10, en: 'And it came to pass, as she spake to Joseph day by day, that he hearkened not unto her, to lie by her, or to be with her.', pt: 'E como ela falava a José dia após dia, ele não lhe dava ouvidos para se deitar com ela ou para estar com ela.' },
    { v: 11, en: 'And it came to pass about this time, that Joseph went into the house to do his business; and there was none of the men of the house there within.', pt: 'Certo dia, José entrou na casa para fazer o seu trabalho; e não havia nenhum dos homens da casa ali dentro.' },
    { v: 12, en: 'And she caught him by his garment, saying, Lie with me: and he left his garment in her hand, and fled, and got him out.', pt: 'Ela o agarrou pela roupa, dizendo: Deita-te comigo; e ele deixou a sua roupa em sua mão e fugiu, saindo para fora.' },
    { v: 13, en: 'And it came to pass, when she saw that he had left his garment in her hand, and was fled forth,', pt: 'Quando ela viu que ele havia deixado a sua roupa em sua mão e havia fugido para fora,' },
    { v: 14, en: 'That she called unto the men of her house, and spake unto them, saying, See, he hath brought in an Hebrew unto us to mock us; he came in unto me to lie with me, and I cried with a loud voice:', pt: 'chamou os homens da sua casa e lhes falou: Vede, ele nos trouxe um hebreu para nos ultrajar; ele veio a mim para se deitar comigo, e eu gritei com alta voz.' },
    { v: 15, en: 'And it came to pass, when he heard that I lifted up my voice and cried, that he left his garment with me, and fled, and got him out.', pt: 'E quando ouviu que eu levantei a voz e gritei, ele deixou a sua roupa comigo e fugiu para fora.' },
    { v: 16, en: 'And she laid up his garment by her, until his lord came home.', pt: 'Ela deixou a sua roupa consigo até que o seu senhor chegou em casa.' },
    { v: 17, en: 'And she spake unto him according to these words, saying, The Hebrew servant, which thou hast brought unto us, came in unto me to mock me:', pt: 'E falou-lhe segundo estas palavras: O servo hebreu que nos trouxeste veio a mim para me ultrajar.' },
    { v: 18, en: 'And it came to pass, as I lifted up my voice and cried, that he left his garment with me, and fled out.', pt: 'E quando levantei a voz e gritei, ele deixou a sua roupa comigo e fugiu para fora.' },
    { v: 19, en: 'And it came to pass, when his master heard the words of his wife, which she spake unto him, saying, After this manner did thy servant to me; that his wrath was kindled.', pt: 'E quando o seu senhor ouviu as palavras de sua mulher que lhe falou, dizendo: O teu servo fez assim comigo, a sua ira se acendeu.' },
    { v: 20, en: 'And Joseph\'s master took him, and put him into the prison, a place where the king\'s prisoners were bound: and he was there in the prison.', pt: 'O senhor de José o tomou e o pôs na prisão, no lugar onde os presos do rei eram detidos; e ele ficou ali na prisão.' },
    { v: 21, en: 'But the LORD was with Joseph, and shewed him mercy, and gave him favour in the sight of the keeper of the prison.', pt: 'Mas o Senhor estava com José e lhe mostrou misericórdia, e lhe deu graça aos olhos do guarda da prisão.' },
    { v: 22, en: 'And the keeper of the prison committed to Joseph\'s hand all the prisoners that were in the prison; and whatsoever they did there, he was the doer of it.', pt: 'O guarda da prisão entregou nas mãos de José todos os presos que estavam na prisão; e tudo o que se fazia ali, era ele quem fazia.' },
    { v: 23, en: 'The keeper of the prison looked not to any thing that was under his hand; because the LORD was with him, and that which he did, the LORD made it to prosper.', pt: 'O guarda da prisão não se preocupava com nada do que estava sob a sua mão, porque o Senhor estava com ele; e o que ele fazia, o Senhor fazia prosperar.' },
  ],
  40: [
    { v: 1, en: 'And it came to pass after these things, that the butler of the king of Egypt and his baker had offended their lord the king of Egypt.', pt: 'Depois dessas coisas, o copeiro-mor do rei do Egito e o padeiro-mor ofenderam o seu senhor, o rei do Egito.' },
    { v: 2, en: 'And Pharaoh was wroth against two of his officers, against the chief of the butlers, and against the chief of the bakers.', pt: 'O faraó ficou irado contra dois dos seus oficiais, contra o copeiro-mor e contra o padeiro-mor.' },
    { v: 3, en: 'And he put them in ward in the house of the captain of the guard, into the prison, the place where Joseph was bound.', pt: 'E os pôs sob guarda na casa do capitão da guarda, na prisão, o lugar onde José estava preso.' },
    { v: 4, en: 'And the captain of the guard charged Joseph with them, and he served them: and they continued a season in ward.', pt: 'O capitão da guarda encarregou José de cuidar deles, e ele os servia; e eles ficaram algum tempo sob guarda.' },
    { v: 5, en: 'And they dreamed a dream both of them, each man his dream in one night, each man according to the interpretation of his dream, the butler and the baker of the king of Egypt, which were bound in the prison.', pt: 'E ambos tiveram um sonho, cada um o seu sonho na mesma noite, cada um com a sua própria interpretação, o copeiro-mor e o padeiro-mor do rei do Egito, que estavam presos na prisão.' },
    { v: 6, en: 'And Joseph came in unto them in the morning, and looked upon them, and, behold, they were sad.', pt: 'José veio a eles de manhã e os viu, e eis que estavam tristes.' },
    { v: 7, en: 'And he asked Pharaoh\'s officers that were with him in the ward of his lord\'s house, saying, Wherefore look ye so sadly to day?', pt: 'E perguntou aos oficiais do faraó que estavam com ele na guarda da casa do seu senhor: Por que estais com tal aparência triste hoje?' },
    { v: 8, en: 'And they said unto him, We have dreamed a dream, and there is no interpreter of it. And Joseph said unto them, Do not interpretations belong to God? tell me them, I pray you.', pt: 'E eles lhe disseram: Tivemos um sonho, e não há quem o interprete. E José lhes disse: Não pertencem a Deus as interpretações? Contai-mo, por favor.' },
    { v: 9, en: 'And the chief butler told his dream to Joseph, and said to him, In my dream, behold, a vine was before me;', pt: 'O copeiro-mor contou o seu sonho a José e disse-lhe: No meu sonho, eis que havia uma videira diante de mim.' },
    { v: 10, en: 'And in the vine were three branches: and it was as though it budded, and her blossoms shot forth; and the clusters thereof brought forth ripe grapes:', pt: 'E na videira havia três ramos; e era como se brotasse, e as flores desabrochavam; e os seus cachos produziam uvas maduras.' },
    { v: 11, en: 'And Pharaoh\'s cup was in my hand: and I took the grapes, and pressed them into Pharaoh\'s cup, and I gave the cup into Pharaoh\'s hand.', pt: 'E o cálice do faraó estava em minha mão; e eu tomei as uvas, as espremi no cálice do faraó e dei o cálice na mão do faraó.' },
    { v: 12, en: 'And Joseph said unto him, This is the interpretation of it: The three branches are three days:', pt: 'José lhe disse: Esta é a sua interpretação: Os três ramos são três dias.' },
    { v: 13, en: 'Yet within three days shall Pharaoh lift up thine head, and restore thee unto thy place: and thou shalt deliver Pharaoh\'s cup into his hand, after the former manner when thou wast his butler.', pt: 'Dentro de três dias o faraó te levantará e te restaurará ao teu lugar; e darás o cálice do faraó em sua mão, como era teu costume anteriormente quando eras seu copeiro.' },
    { v: 14, en: 'But think on me when it shall be well with thee, and shew kindness, I pray thee, unto me, and make mention of me unto Pharaoh, and bring me out of this house:', pt: 'Mas lembra-te de mim quando te for bem, e mostra-me bondade, por favor, e faz menção de mim ao faraó, e me tira desta prisão.' },
    { v: 15, en: 'For indeed I was stolen away out of the land of the Hebrews: and here also have I done nothing that they should put me into the dungeon.', pt: 'Pois fui de fato roubado da terra dos hebreus; e aqui também não fiz nada para que me pusessem na prisão.' },
    { v: 16, en: 'When the chief baker saw that the interpretation was good, he said unto Joseph, I also was in my dream, and, behold, I had three white baskets on my head:', pt: 'O padeiro-mor viu que a interpretação era boa, e disse a José: Eu também estava no meu sonho; e eis que havia três cestos de pão branco sobre a minha cabeça.' },
    { v: 17, en: 'And in the uppermost basket there was of all manner of bakemeats for Pharaoh; and the birds did eat them out of the basket upon my head.', pt: 'E no cesto de cima havia de toda espécie de alimentos assados para o faraó; e as aves os comiam do cesto sobre a minha cabeça.' },
    { v: 18, en: 'And Joseph answered and said, This is the interpretation thereof: The three baskets are three days:', pt: 'José respondeu e disse: Esta é a sua interpretação: Os três cestos são três dias.' },
    { v: 19, en: 'Yet within three days shall Pharaoh lift up thy head from off thee, and shall hang thee on a tree; and the birds shall eat thy flesh from off thee.', pt: 'Dentro de três dias o faraó te levantará da tua cabeça e te enforcará num pau; e as aves comerão a tua carne.' },
    { v: 20, en: 'And it came to pass the third day, which was Pharaoh\'s birthday, that he made a feast unto all his servants: and he lifted up the head of the chief butler and of the chief baker among his servants.', pt: 'Ao terceiro dia, que era o aniversário do faraó, ele fez um banquete a todos os seus servos; e levantou a cabeça do copeiro-mor e a cabeça do padeiro-mor entre os seus servos.' },
    { v: 21, en: 'And he restored the chief butler unto his butlership again; and he gave the cup into Pharaoh\'s hand:', pt: 'E restaurou o copeiro-mor ao seu cargo de copeiro, e ele deu o cálice na mão do faraó.' },
    { v: 22, en: 'But he hanged the chief baker: as Joseph had interpreted to them.', pt: 'Mas o padeiro-mor foi enforcado, como José tinha interpretado para eles.' },
    { v: 23, en: 'Yet did not the chief butler remember Joseph, but forgat him.', pt: 'Mas o copeiro-mor não se lembrou de José e o esqueceu.' },
  ],
  41: [
    { v: 1, en: 'And it came to pass at the end of two full years, that Pharaoh dreamed: and, behold, he stood by the river.', pt: 'Ao fim de dois anos completos, o faraó teve um sonho; e eis que ele estava junto ao rio.' },
    { v: 2, en: 'And, behold, there came up out of the river seven well favoured kine and fatfleshed; and they fed in a meadow.', pt: 'E eis que do rio subiram sete vacas bonitas e gordas; e pastavam no prado.' },
    { v: 3, en: 'And, behold, seven other kine came up after them out of the river, ill favoured and leanfleshed; and stood by the other kine upon the brink of the river.', pt: 'E eis que subiram depois delas sete outras vacas feias e magras; e pararam junto às outras vacas à margem do rio.' },
    { v: 4, en: 'And the ill favoured and leanfleshed kine did eat up the seven well favoured and fat kine. So Pharaoh awoke.', pt: 'E as vacas feias e magras devoraram as sete vacas bonitas e gordas. E o faraó acordou.' },
    { v: 5, en: 'And he slept and dreamed the second time: and, behold, seven ears of corn came up upon one stalk, rank and good.', pt: 'Ele dormiu e sonhou outra vez; e eis que sete espigas de grão subiram em um só caule, gordas e boas.' },
    { v: 6, en: 'And, behold, seven thin ears and blasted with the east wind sprung up after them.', pt: 'E eis que sete espigas magras e queimadas pelo vento leste brotaram depois delas.' },
    { v: 7, en: 'And the seven thin ears devoured the seven rank and full ears. And Pharaoh awoke, and, behold, it was a dream.', pt: 'E as sete espigas magras devoraram as sete espigas gordas e cheias. E o faraó acordou, e eis que era um sonho.' },
    { v: 8, en: 'And it came to pass in the morning that his spirit was troubled; and he sent and called for all the magicians of Egypt, and all the wise men thereof: and Pharaoh told them his dream; but there was none that could interpret them unto Pharaoh.', pt: 'E de manhã o seu espírito ficou perturbado; e ele mandou chamar todos os magos do Egito e todos os seus sábios; e o faraó lhes contou o seu sonho; mas não havia ninguém que os interpretasse ao faraó.' },
    { v: 9, en: 'Then spake the chief butler unto Pharaoh, saying, I do remember my faults this day:', pt: 'Então o copeiro-mor falou ao faraó, dizendo: Lembro-me hoje das minhas faltas.' },
    { v: 10, en: 'Pharaoh was wroth with his servants, and put me in ward in the captain of the guard\'s house, both me and the chief baker:', pt: 'O faraó ficou irado com os seus servos e nos pôs sob guarda na casa do capitão da guarda, a mim e ao padeiro-mor.' },
    { v: 11, en: 'And we dreamed a dream in one night, I and he; we dreamed each man according to the interpretation of his dream.', pt: 'E tivemos um sonho na mesma noite, eu e ele; sonhamos cada um segundo a interpretação do seu sonho.' },
    { v: 12, en: 'And there was there with us a young man, an Hebrew, servant to the captain of the guard; and we told him, and he interpreted to us our dreams; to each man according to his dream he did interpret.', pt: 'E havia ali conosco um jovem hebreu, servo do capitão da guarda; e lhe contamos e ele nos interpretou os nossos sonhos; a cada um segundo o seu sonho, interpretou.' },
    { v: 13, en: 'And it came to pass, as he interpreted to us, so it was; me he restored unto mine office, and him he hanged.', pt: 'E aconteceu como ele nos interpretou; eu fui restaurado ao meu cargo, e aquele foi enforcado.' },
    { v: 14, en: 'Then Pharaoh sent and called Joseph, and they brought him hastily out of the dungeon: and he shaved himself, and changed his raiment, and came in unto Pharaoh.', pt: 'Então o faraó mandou chamar José, e o trouxeram rapidamente da prisão; e ele se barbeou, mudou de veste e veio ao faraó.' },
    { v: 15, en: 'And Pharaoh said unto Joseph, I have dreamed a dream, and there is none that can interpret it: and I have heard say of thee, that thou canst understand a dream to interpret it.', pt: 'O faraó disse a José: Tive um sonho e não há ninguém que o interprete; e ouvi dizer de ti que podes entender um sonho para interpretá-lo.' },
    { v: 16, en: 'And Joseph answered Pharaoh, saying, It is not in me: God shall give Pharaoh an answer of peace.', pt: 'José respondeu ao faraó: Não em mim; Deus dará ao faraó uma resposta de paz.' },
    { v: 17, en: 'And Pharaoh said unto Joseph, In my dream, behold, I stood upon the bank of the river:', pt: 'O faraó disse a José: No meu sonho, eis que eu estava à margem do rio.' },
    { v: 18, en: 'And, behold, there came up out of the river seven kine, fatfleshed and well favoured; and they fed in a meadow:', pt: 'E eis que do rio subiram sete vacas gordas e bonitas; e pastavam no prado.' },
    { v: 19, en: 'And, behold, seven other kine came up after them, poor and very ill favoured and leanfleshed, such as I never saw in all the land of Egypt for badness:', pt: 'E eis que subiram depois delas sete outras vacas débeis, muito feias e magras, tão ruins que nunca vi iguais em toda a terra do Egito.' },
    { v: 20, en: 'And the lean and the ill favoured kine did eat up the first seven fat kine:', pt: 'E as vacas magras e feias devoraram as primeiras sete vacas gordas.' },
    { v: 21, en: 'And when they had eaten them up, it could not be known that they had eaten them; but they were still ill favoured, as at the beginning. So I awoke.', pt: 'E depois de as haverem devorado, não se podia saber que as tinham devorado; mas continuavam feias como no começo. E acordei.' },
    { v: 22, en: 'And I saw in my dream, and, behold, seven ears came up in one stalk, full and good:', pt: 'Vi no meu sonho, e eis que sete espigas subiram em um só caule, cheias e boas.' },
    { v: 23, en: 'And, behold, seven ears, withered, thin, and blasted with the east wind, sprung up after them:', pt: 'E eis que sete espigas murchas, magras e queimadas pelo vento leste brotaram depois delas.' },
    { v: 24, en: 'And the thin ears devoured the seven good ears: and I told this unto the magicians; but there was none that could declare it to me.', pt: 'E as espigas magras devoraram as sete espigas boas; e contei isso aos magos, mas nenhum me pôde explicar.' },
    { v: 25, en: 'And Joseph said unto Pharaoh, The dream of Pharaoh is one: God hath shewed Pharaoh what he is about to do.', pt: 'José disse ao faraó: O sonho do faraó é um só; Deus mostrou ao faraó o que está prestes a fazer.' },
    { v: 26, en: 'The seven good kine are seven years; and the seven good ears are seven years: the dream is one.', pt: 'As sete vacas boas são sete anos; e as sete espigas boas são sete anos; o sonho é um só.' },
    { v: 27, en: 'And the seven thin and ill favoured kine that came up after them are seven years; and the seven empty ears blasted with the east wind shall be seven years of famine.', pt: 'E as sete vacas magras e feias que subiram depois delas são sete anos; e as sete espigas vazias queimadas pelo vento leste serão sete anos de fome.' },
    { v: 28, en: 'This is the thing which I have spoken unto Pharaoh: What God is about to do he sheweth unto Pharaoh.', pt: 'É o que disse ao faraó; o que Deus está prestes a fazer, ele mostrou ao faraó.' },
    { v: 29, en: 'Behold, there come seven years of great plenty throughout all the land of Egypt:', pt: 'Eis que virão sete anos de grande abundância em toda a terra do Egito.' },
    { v: 30, en: 'And there shall arise after them seven years of famine; and all the plenty shall be forgotten in the land of Egypt; and the famine shall consume the land;', pt: 'E depois virão sete anos de fome; e toda a abundância será esquecida na terra do Egito; e a fome consumirá a terra.' },
    { v: 31, en: 'And the plenty shall not be known in the land by reason of that famine following; for it shall be very grievous.', pt: 'E a abundância não será conhecida na terra por causa da fome que se seguirá; pois será muito rigorosa.' },
    { v: 32, en: 'And for that the dream was doubled unto Pharaoh twice; it is because the thing is established by God, and God will shortly bring it to pass.', pt: 'E por ter o sonho sido repetido ao faraó duas vezes, é porque a coisa está confirmada por Deus, e Deus a realizará em breve.' },
    { v: 33, en: 'Now therefore let Pharaoh look out a man discreet and wise, and set him over the land of Egypt.', pt: 'Portanto, que o faraó procure um homem prudente e sábio, e o constitua sobre a terra do Egito.' },
    { v: 34, en: 'Let Pharaoh do this, and let him appoint officers over the land, and take up the fifth part of the land of Egypt in the seven plenteous years.', pt: 'Que o faraó faça isso, e nomeie administradores sobre a terra, e recolha a quinta parte da terra do Egito nos sete anos de abundância.' },
    { v: 35, en: 'And let them gather all the food of those good years that come, and lay up corn under the hand of Pharaoh, and let them keep food in the cities.', pt: 'E que recolham todos os alimentos destes anos bons que vêm, e acumulem grãos sob a mão do faraó, e guardem alimento nas cidades.' },
    { v: 36, en: 'And that food shall be for store to the land against the seven years of famine, which shall be in the land of Egypt; that the land perish not through the famine.', pt: 'E esse alimento será reserva para a terra contra os sete anos de fome que haverá na terra do Egito; para que a terra não pereça pela fome.' },
    { v: 37, en: 'And the thing was good in the eyes of Pharaoh, and in the eyes of all his servants.', pt: 'E a coisa pareceu boa aos olhos do faraó e aos olhos de todos os seus servos.' },
    { v: 38, en: 'And Pharaoh said unto his servants, Can we find such a one as this is, a man in whom the Spirit of God is?', pt: 'E o faraó disse aos seus servos: Podemos encontrar alguém como este, um homem em quem está o Espírito de Deus?' },
    { v: 39, en: 'And Pharaoh said unto Joseph, Forasmuch as God hath shewed thee all this, there is none so discreet and wise as thou art:', pt: 'Então o faraó disse a José: Visto que Deus te mostrou tudo isso, não há ninguém tão prudente e sábio quanto tu.' },
    { v: 40, en: 'Thou shalt be over my house, and according unto thy word shall all my people be ruled: only in the throne will I be greater than thou.', pt: 'Tu estarás sobre a minha casa, e segundo a tua palavra todo o meu povo se governará; somente no trono eu serei maior do que tu.' },
    { v: 41, en: 'And Pharaoh said unto Joseph, See, I have set thee over all the land of Egypt.', pt: 'E o faraó disse a José: Veja, eu te constituo sobre toda a terra do Egito.' },
    { v: 42, en: 'And Pharaoh took off his ring from his hand, and put it upon Joseph\'s hand, and arrayed him in vestures of fine linen, and put a gold chain about his neck;', pt: 'E o faraó tirou o seu anel da mão e o pôs na mão de José, e o vestiu com roupas de linho fino, e pôs um colar de ouro ao seu pescoço.' },
    { v: 43, en: 'And he made him to ride in the second chariot which he had; and they cried before him, Bow the knee: and he made him ruler over all the land of Egypt.', pt: 'E o fez andar no segundo carro que tinha; e clamavam diante dele: Ajoelhai! E o constituiu sobre toda a terra do Egito.' },
    { v: 44, en: 'And Pharaoh said unto Joseph, I am Pharaoh, and without thee shall no man lift up his hand or foot in all the land of Egypt.', pt: 'E o faraó disse a José: Eu sou o faraó, e sem ti nenhum homem levantará a sua mão ou o seu pé em toda a terra do Egito.' },
    { v: 45, en: 'And Pharaoh called Joseph\'s name Zaphnathpaaneah; and he gave him to wife Asenath the daughter of Potipherah priest of On. And Joseph went out over all the land of Egypt.', pt: 'E o faraó chamou o nome de José Zafenate-Panéia; e lhe deu por mulher Asenet, filha de Potífera, sacerdote de Om. E José saiu sobre toda a terra do Egito.' },
    { v: 46, en: 'And Joseph was thirty years old when he stood before Pharaoh king of Egypt. And Joseph went out from the presence of Pharaoh, and went throughout all the land of Egypt.', pt: 'E José tinha trinta anos quando se apresentou perante o faraó, rei do Egito. E José saiu da presença do faraó e percorreu toda a terra do Egito.' },
    { v: 47, en: 'And in the seven plenteous years the earth brought forth by handfuls.', pt: 'Nos sete anos de abundância a terra produziu em punhados.' },
    { v: 48, en: 'And he gathered up all the food of the seven years, which were in the land of Egypt, and laid up the food in the cities: the food of the field, which was round about every city, laid he up in the same.', pt: 'E ele recolheu todo o alimento dos sete anos que havia na terra do Egito, e guardou o alimento nas cidades; o alimento do campo ao redor de cada cidade, depositou na mesma.' },
    { v: 49, en: 'And Joseph gathered corn as the sand of the sea, very much, until he left numbering; for it was without number.', pt: 'E José acumulou grão como a areia do mar, em grande quantidade, até que parou de contar; pois era sem número.' },
    { v: 50, en: 'And unto Joseph were born two sons before the years of famine came, which Asenath the daughter of Potipherah priest of On bare unto him.', pt: 'E a José nasceram dois filhos antes que viessem os anos de fome, os quais Asenet, filha de Potífera, sacerdote de Om, lhe deu à luz.' },
    { v: 51, en: 'And Joseph called the name of the firstborn Manasseh: For God, said he, hath made me forget all my toil, and all my father\'s house.', pt: 'E José chamou o nome do primogênito Manassés, pois disse: Deus me fez esquecer todo o meu trabalho e toda a casa de meu pai.' },
    { v: 52, en: 'And the name of the second called he Ephraim: For God hath caused me to be fruitful in the land of my affliction.', pt: 'E o nome do segundo chamou Efraim, pois disse: Deus me fez fecundo na terra da minha aflição.' },
    { v: 53, en: 'And the seven years of plenteousness, that was in the land of Egypt, were ended.', pt: 'E os sete anos de abundância que havia na terra do Egito chegaram ao fim.' },
    { v: 54, en: 'And the seven years of dearth began to come, according as Joseph had said: and the dearth was in all lands; but in all the land of Egypt there was bread.', pt: 'E os sete anos de fome começaram a vir, como José havia dito; e havia fome em todas as terras; mas em toda a terra do Egito havia pão.' },
    { v: 55, en: 'And when all the land of Egypt was famished, the people cried to Pharaoh for bread: and Pharaoh said unto all the Egyptians, Go unto Joseph; what he saith to you, do.', pt: 'E quando toda a terra do Egito teve fome, o povo clamou ao faraó por pão; e o faraó disse a todos os egípcios: Ide a José; o que ele vos disser, fazei.' },
    { v: 56, en: 'And the famine was over all the face of the earth: And Joseph opened all the storehouses, and sold unto the Egyptians; and the famine waxed sore in the land of Egypt.', pt: 'E a fome estava sobre toda a face da terra; e José abriu todos os celeiros e vendeu aos egípcios; e a fome se agravou na terra do Egito.' },
    { v: 57, en: 'And all countries came into Egypt to Joseph for to buy corn; because that the famine was so sore in all lands.', pt: 'E todos os países vinheram ao Egito, a José, para comprar grãos; porque a fome era rigorosa em todas as terras.' },
  ],
  42: [
    { v: 1, en: 'Now when Jacob saw that there was corn in Egypt, Jacob said unto his sons, Why do ye look one upon another?', pt: 'Quando Jacó soube que havia grão no Egito, Jacó disse a seus filhos: Por que ficais olhando uns para os outros?' },
    { v: 2, en: 'And he said, Behold, I have heard that there is corn in Egypt: get you down thither, and buy for us from thence; that we may live, and not die.', pt: 'E disse: Ouvi dizer que há grão no Egito; descei lá e comprai para nós de lá, para que vivamos e não morramos.' },
    { v: 3, en: 'And Joseph\'s ten brethren went down to buy corn in Egypt.', pt: 'E os dez irmãos de José desceram a comprar grão no Egito.' },
    { v: 4, en: 'But Benjamin, Joseph\'s brother, Jacob sent not with his brethren; for he said, Lest peradventure mischief befall him.', pt: 'Mas Jacó não enviou Benjamim, irmão de José, com seus irmãos; pois disse: Para que não lhe aconteça algum mal.' },
    { v: 5, en: 'And the sons of Israel came to buy corn among those that came: for the famine was in the land of Canaan.', pt: 'E os filhos de Israel vieram comprar entre os que vinham; pois havia fome na terra de Canaã.' },
    { v: 6, en: 'And Joseph was the governor over the land, and he it was that sold to all the people of the land: and Joseph\'s brethren came, and bowed down themselves before him with their faces to the earth.', pt: 'E José era o governador sobre a terra, e era ele quem vendia a todo o povo da terra; e os irmãos de José vieram e se inclinaram diante dele com o rosto em terra.' },
    { v: 7, en: 'And Joseph saw his brethren, and he knew them, but made himself strange unto them, and spake roughly unto them; and he said unto them, Whence come ye? And they said, From the land of Canaan to buy food.', pt: 'E José viu os seus irmãos e os reconheceu, mas se fez estranho a eles e lhes falou asperamente; e lhes disse: De onde vindes? E eles disseram: Da terra de Canaã, para comprar alimento.' },
    { v: 8, en: 'And Joseph knew his brethren, but they knew not him.', pt: 'E José reconheceu os seus irmãos, mas eles não o reconheceram.' },
    { v: 9, en: 'And Joseph remembered the dreams which he dreamed of them, and said unto them, Ye are spies; to see the nakedness of the land ye are come.', pt: 'E José se lembrou dos sonhos que havia tido sobre eles, e lhes disse: Vós sois espias; viestes para ver a nudez da terra.' },
    { v: 10, en: 'And they said unto him, Nay, my lord, but to buy food are thy servants come.', pt: 'E eles lhe disseram: Não, meu senhor; os teus servos vieram comprar alimento.' },
    { v: 11, en: 'We are all one man\'s sons; we are true men, thy servants are no spies.', pt: 'Somos todos filhos de um só homem; somos homens honestos; os teus servos não são espias.' },
    { v: 12, en: 'And he said unto them, Nay, but to see the nakedness of the land ye are come.', pt: 'E ele lhes disse: Não; viestes para ver a nudez da terra.' },
    { v: 13, en: 'And they said, Thy servants are twelve brethren, the sons of one man in the land of Canaan; and, behold, the youngest is this day with our father, and one is not.', pt: 'E eles disseram: Os teus servos são doze irmãos, filhos de um só homem na terra de Canaã; e eis que o mais novo está hoje com nosso pai, e um não existe mais.' },
    { v: 14, en: 'And Joseph said unto them, That is it that I spake unto you, saying, Ye are spies:', pt: 'E José lhes disse: É o que vos falei, dizendo: Vós sois espias.' },
    { v: 15, en: 'Hereby ye shall be proved: By the life of Pharaoh ye shall not go forth hence, except your youngest brother come hither.', pt: 'Com isto sereis provados: pela vida do faraó, não saireis daqui, exceto se o vosso irmão mais novo vier aqui.' },
    { v: 16, en: 'Send one of you, and let him fetch your brother, and ye shall be kept in prison, that your words may be proved, whether there be any truth in you: or else by the life of Pharaoh surely ye are spies.', pt: 'Enviai um de vós, e que traga o vosso irmão, e vós ficareis presos, para que as vossas palavras sejam provadas, se há alguma verdade em vós; ou então, pela vida do faraó, certamente sois espias.' },
    { v: 17, en: 'And he put them all together into ward three days.', pt: 'E os pôs todos juntos sob guarda três dias.' },
    { v: 18, en: 'And Joseph said unto them the third day, This do, and live; for I fear God:', pt: 'E José lhes disse no terceiro dia: Fazei isso e vivereis; pois temo a Deus.' },
    { v: 19, en: 'If ye be true men, let one of your brethren be bound in the house of your prison: go ye, carry corn for the famine of your houses:', pt: 'Se sois homens honestos, que fique um de vossos irmãos preso na prisão; ide vós, e levai grão para a fome de vossas casas.' },
    { v: 20, en: 'But bring your youngest brother unto me; so shall your words be verified, and ye shall not die. And they did so.', pt: 'Mas trazei o vosso irmão mais novo a mim; assim as vossas palavras serão verificadas, e não morrereis. E eles assim fizeram.' },
    { v: 21, en: 'And they said one to another, We are verily guilty concerning our brother, in that we saw the anguish of his soul, when he besought us, and we would not hear; therefore is this distress come upon us.', pt: 'E disseram uns aos outros: Certamente somos culpados a respeito de nosso irmão, porque vimos a angústia da sua alma quando nos suplicou, e não lhe demos ouvidos; por isso esta angústia nos sobreveio.' },
    { v: 22, en: 'And Reuben answered them, saying, Spake I not unto you, saying, Do not sin against the child; and ye would not hear? therefore, behold, also his blood is required.', pt: 'E Rúben lhes respondeu: Não vos disse eu: Não pequeis contra o menino; e não me ouvis? Portanto, eis que também o seu sangue é requerido.' },
    { v: 23, en: 'And they knew not that Joseph understood them; for he spake unto them by an interpreter.', pt: 'E eles não sabiam que José os entendia; pois havia um intérprete entre eles.' },
    { v: 24, en: 'And he turned himself about from them, and wept; and returned to them again, and communed with them, and took from them Simeon, and bound him before their eyes.', pt: 'E se afastou deles e chorou; e voltou a eles, e lhes falou; e tomou Simeão deles e o amarrou diante dos seus olhos.' },
    { v: 25, en: 'Then Joseph commanded to fill their sacks with corn, and to restore every man\'s money into his sack, and to give them provision for the way: and thus did he unto them.', pt: 'Então José ordenou que enchessem os seus sacos de grão, e que devolvessem o dinheiro de cada um no seu saco, e que lhes dessem provisão para o caminho; e assim lhes foi feito.' },
    { v: 26, en: 'And they laded their asses with the corn, and departed thence.', pt: 'E carregaram os seus jumentos com o grão e partiram dali.' },
    { v: 27, en: 'And as one of them opened his sack to give his ass provender in the inn, he espied his money; for, behold, it was in his sack\'s mouth.', pt: 'E quando um deles abriu o seu saco para dar forragem ao seu jumento na hospedaria, viu o seu dinheiro; e eis que estava na boca do seu saco.' },
    { v: 28, en: 'And he said unto his brethren, My money is restored; and, lo, it is even in my sack: and their heart failed them, and they were afraid, saying one to another, What is this that God hath done unto us?', pt: 'E disse a seus irmãos: O meu dinheiro foi devolvido; e eis que está no meu saco; e o seu coração desmaiou, e ficaram com medo, dizendo uns aos outros: Que é isso que Deus nos fez?' },
    { v: 29, en: 'And they came unto Jacob their father unto the land of Canaan, and told him all that befell unto them; saying,', pt: 'E foram a Jacó, seu pai, à terra de Canaã, e lhe contaram tudo o que lhes havia acontecido, dizendo:' },
    { v: 30, en: 'The man, who is the lord of the land, spake roughly to us, and took us for spies of the country.', pt: 'O homem, que é o senhor daquela terra, nos falou asperamente e nos tomou por espias do país.' },
    { v: 31, en: 'And we said unto him, We are true men; we are no spies:', pt: 'E lhe dissemos: Somos homens honestos; não somos espias.' },
    { v: 32, en: 'We be twelve brethren, sons of our father; one is not, and the youngest is this day with our father in the land of Canaan.', pt: 'Somos doze irmãos, filhos de nosso pai; um não existe mais, e o mais novo está hoje com nosso pai na terra de Canaã.' },
    { v: 33, en: 'And the man, the lord of the country, said unto us, Hereby shall I know that ye are true men; leave one of your brethren here with me, and take food for the famine of your households, and be gone:', pt: 'E o homem, o senhor do país, nos disse: Assim saberei que sois homens honestos; deixai um de vossos irmãos aqui comigo, e tomai alimento para a fome das vossas casas e ide.' },
    { v: 34, en: 'And bring your youngest brother unto me: then shall I know that ye are no spies, but that ye are true men: so will I deliver you your brother, and ye shall traffick in the land.', pt: 'E trazei o vosso irmão mais novo a mim; então saberei que não sois espias, mas homens honestos; assim vos entregarei o vosso irmão, e negociareis na terra.' },
    { v: 35, en: 'And it came to pass as they emptied their sacks, that, behold, every man\'s bundle of money was in his sack: and when both they and their father saw the bundles of money, they were afraid.', pt: 'E aconteceu que quando esvaziavam os seus sacos, eis que o pacote de dinheiro de cada um estava no seu saco; e quando tanto eles como seu pai viram os pacotes de dinheiro, ficaram com medo.' },
    { v: 36, en: 'And Jacob their father said unto them, Me have ye bereaved of my children: Joseph is not, and Simeon is not, and ye will take Benjamin away: all these things are against me.', pt: 'E Jacó, pai deles, lhes disse: Me privais dos meus filhos; José não existe mais, Simeão não existe mais, e quereis tomar Benjamim; todas estas coisas são contra mim.' },
    { v: 37, en: 'And Reuben spake unto his father, saying, Slay my two sons, if I bring him not to thee: deliver him into my hand, and I will bring him to thee again.', pt: 'E Rúben falou a seu pai: Mata os meus dois filhos se eu não te trouxer; entrega-o em minha mão, e eu o trarei de volta.' },
    { v: 38, en: 'And he said, My son shall not go down with you; for his brother is dead, and he is left alone: if mischief befall him by the way in the which ye go, then shall ye bring down my gray hairs with sorrow to the grave.', pt: 'Mas ele disse: Meu filho não descerá convosco; pois o seu irmão está morto e só ele restou; se lhe acontecer algum mal no caminho pelo qual ides, fareis descer as minhas cãs com tristeza ao sepulcro.' },
  ],
  43: [
    { v: 1, en: 'And the famine was sore in the land.', pt: 'E a fome era rigorosa na terra.' },
    { v: 2, en: 'And it came to pass, when they had eaten up the corn which they had brought out of Egypt, their father said unto them, Go again, buy us a little food.', pt: 'E aconteceu que quando acabaram de comer o grão que haviam trazido do Egito, seu pai lhes disse: Voltai e comprai-nos um pouco de alimento.' },
    { v: 3, en: 'And Judah spake unto him, saying, The man did solemnly protest unto us, saying, Ye shall not see my face, except your brother be with you.', pt: 'E Judá lhe falou: O homem nos protestou solenemente, dizendo: Não vereis a minha face, exceto se o vosso irmão estiver convosco.' },
    { v: 4, en: 'If thou wilt send our brother with us, we will go down and buy thee food:', pt: 'Se enviares o nosso irmão conosco, desceremos e te compraremos alimento.' },
    { v: 5, en: 'But if thou wilt not send him, we will not go down: for the man said unto us, Ye shall not see my face, except your brother be with you.', pt: 'Mas se não o enviares, não desceremos; pois o homem nos disse: Não vereis a minha face, exceto se o vosso irmão estiver convosco.' },
    { v: 6, en: 'And Israel said, Wherefore dealt ye so ill with me, as to tell the man whether ye had yet a brother?', pt: 'E Israel disse: Por que me fizestes tão mal, dizendo ao homem se ainda tindes irmão?' },
    { v: 7, en: 'And they said, The man asked us straitly of our state, and of our kindred, saying, Is your father yet alive? have ye another brother? and we told him according to the tenor of these words: could we certainly know that he would say, Bring your brother down?', pt: 'E eles disseram: O homem nos perguntou expressamente sobre nós e sobre a nossa parentela, dizendo: Vosso pai ainda vive? Tendes outro irmão? E lhe respondemos segundo o conteúdo dessas perguntas; podíamos nós saber com certeza que ele diria: Trazei o vosso irmão?' },
    { v: 8, en: 'And Judah said unto Israel his father, Send the lad with me, and we will arise and go; that we may live, and not die, both we, and thou, and also our little ones.', pt: 'E Judá disse a Israel, seu pai: Envia o jovem comigo, e nos levantaremos e iremos; para que vivamos e não morramos, tanto nós como tu e também as nossas crianças.' },
    { v: 9, en: 'I will be surety for him; of my hand shalt thou require him: if I bring him not unto thee, and set him before thee, then let me bear the blame for ever:', pt: 'Eu serei garante por ele; da minha mão o reclamarás; se eu não te trouxer e o puser diante de ti, então serei culpado perante ti para sempre.' },
    { v: 10, en: 'For except we had lingered, surely now we had returned this second time.', pt: 'Pois se não tivéssemos tardado, certamente já teríamos voltado desta segunda vez.' },
    { v: 11, en: 'And their father Israel said unto them, If it must be so now, do this; take of the best fruits in the land in your vessels, and carry down the man a present, a little balm, and a little honey, spices, and myrrh, nuts, and almonds:', pt: 'E Israel, pai deles, lhes disse: Se assim deve ser, fazei isso; tomai das melhores frutas da terra nos vossos vasos, e levai ao homem um presente, um pouco de bálsamo, um pouco de mel, especiarias e mirra, nozes e amêndoas.' },
    { v: 12, en: 'And take double money in your hand; and the money that was brought again in the mouth of your sacks, carry it again in your hand; peradventure it was an oversight:', pt: 'E tomai o dobro do dinheiro em vossos mãos; e o dinheiro que foi devolvido na boca dos vossos sacos, tornai a levá-lo em vossas mãos; talvez foi um descuido.' },
    { v: 13, en: 'Take also your brother, and arise, go again unto the man:', pt: 'Tomai também o vosso irmão, levantai-vos e voltai ao homem.' },
    { v: 14, en: 'And God Almighty give you mercy before the man, that he may send away your other brother, and Benjamin. If I be bereaved of my children, I am bereaved.', pt: 'E que o Deus Todo-Poderoso vos dê misericórdia diante do homem, para que ele vos liberte o outro irmão e Benjamim. Se eu for privado dos meus filhos, serei privado.' },
    { v: 15, en: 'And the men took that present, and they took double money in their hand, and Benjamin; and rose up, and went down to Egypt, and stood before Joseph.', pt: 'E os homens tomaram esse presente, e tomaram o dobro do dinheiro em suas mãos e Benjamim; e se levantaram e desceram ao Egito, e se apresentaram diante de José.' },
    { v: 16, en: 'And when Joseph saw Benjamin with them, he said to the ruler of his house, Bring these men home, and slay, and make ready; for these men shall dine with me at noon.', pt: 'Quando José viu Benjamim com eles, disse ao mordomo da sua casa: Leva esses homens à casa, e mata o animal e prepara; pois esses homens comerão comigo ao meio-dia.' },
    { v: 17, en: 'And the man did as Joseph bade; and the man brought the men into Joseph\'s house.', pt: 'E o homem fez como José ordenou; e o homem levou os homens à casa de José.' },
    { v: 18, en: 'And the men were afraid, because they were brought into Joseph\'s house; and they said, Because of the money that was returned in our sacks at the first time are we brought in; that he may seek occasion against us, and fall upon us, and take us for bondmen, and our asses.', pt: 'E os homens ficaram com medo porque foram levados à casa de José; e disseram: Por causa do dinheiro que foi devolvido nos nossos sacos da primeira vez somos levados; para que ele procure pretexto contra nós, caia sobre nós, nos tome por servos e tome os nossos jumentos.' },
    { v: 19, en: 'And they came near to the steward of Joseph\'s house, and they communed with him at the door of the house,', pt: 'E se aproximaram do mordomo da casa de José, e lhe falaram à porta da casa,' },
    { v: 20, en: 'And said, O sir, we came indeed down at the first time to buy food:', pt: 'e disseram: Ó senhor, na verdade descemos da primeira vez para comprar alimento.' },
    { v: 21, en: 'And it came to pass, when we came to the inn, that we opened our sacks, and, behold, every man\'s money was in the mouth of his sack, our money in full weight: and we have brought it again in our hand.', pt: 'E aconteceu que quando chegamos à hospedaria, abrimos os nossos sacos; e eis que o dinheiro de cada um estava na boca do seu saco, o nosso dinheiro em peso total; e o tornamos a trazer em nossas mãos.' },
    { v: 22, en: 'And other money have we brought down in our hands to buy food: we cannot tell who put our money in our sacks.', pt: 'E trouxemos outro dinheiro em nossas mãos para comprar alimento; não sabemos quem pôs o nosso dinheiro nos nossos sacos.' },
    { v: 23, en: 'And he said, Peace be to you, fear not: your God, and the God of your father, hath given you treasure in your sacks: I had your money. And he brought Simeon out unto them.', pt: 'E ele disse: Paz a vós, não tenhais medo; o vosso Deus e o Deus de vosso pai vos deu tesouro nos vossos sacos; eu tinha o vosso dinheiro. E lhes trouxe Simeão.' },
    { v: 24, en: 'And the man brought the men into Joseph\'s house, and gave them water, and they washed their feet; and he gave their asses provender.', pt: 'E o homem levou os homens à casa de José, e lhes deu água, e lavaram os seus pés; e deu forragem aos seus jumentos.' },
    { v: 25, en: 'And they made ready the present against Joseph came at noon: for they heard that they should eat bread there.', pt: 'E prepararam o presente para quando José viesse ao meio-dia; pois ouviram que ali comeriam pão.' },
    { v: 26, en: 'And when Joseph came home, they brought him the present which was in their hand into the house, and bowed themselves to him to the earth.', pt: 'E quando José chegou em casa, trouxeram-lhe o presente que estava em suas mãos, para dentro da casa, e se inclinaram diante dele em terra.' },
    { v: 27, en: 'And he asked them of their welfare, and said, Is your father well, the old man of whom ye spake? Is he yet alive?', pt: 'E lhes perguntou sobre o seu bem-estar e disse: Está bem o vosso pai, o ancião de quem falastes? Ainda vive?' },
    { v: 28, en: 'And they answered, Thy servant our father is in good health, he is yet alive. And they bowed down their heads, and made obeisance.', pt: 'E eles responderam: O teu servo, nosso pai, está com saúde; ainda vive. E se inclinaram e fizeram reverência.' },
    { v: 29, en: 'And he lifted up his eyes, and saw his brother Benjamin, his mother\'s son, and said, Is this your younger brother, of whom ye spake unto me? And he said, God be gracious unto thee, my son.', pt: 'E ele levantou os seus olhos e viu Benjamim, seu irmão, filho de sua mãe, e disse: É este o vosso irmão mais novo de quem me falastes? E disse: Deus seja gracioso a ti, meu filho.' },
    { v: 30, en: 'And Joseph made haste; for his bowels did yearn upon his brother: and he sought where to weep; and he entered into his chamber, and wept there.', pt: 'E José se apressou; pois as suas entranhas se comoveram para com o seu irmão; e procurou onde chorar; e entrou no seu quarto, e chorou ali.' },
    { v: 31, en: 'And he washed his face, and went out, and refrained himself, and said, Set on bread.', pt: 'E lavou o seu rosto e saiu; e se conteve e disse: Ponde o pão.' },
    { v: 32, en: 'And they set on for him by himself, and for them by themselves, and for the Egyptians, which did eat with him, by themselves: because the Egyptians might not eat bread with the Hebrews; for that is an abomination unto the Egyptians.', pt: 'E puseram para ele sozinho, e para eles separadamente, e para os egípcios que comiam com ele separadamente; porque os egípcios não podiam comer pão com os hebreus; pois isso é abominação para os egípcios.' },
    { v: 33, en: 'And they sat before him, the firstborn according to his birthright, and the youngest according to his youth: and the men marvelled one at another.', pt: 'E se sentaram diante dele, o primogênito segundo o seu direito de primogenitura e o mais novo segundo a sua juventude; e os homens se admiraram uns dos outros.' },
    { v: 34, en: 'And he took and sent messes unto them from before him: but Benjamin\'s mess was five times so much as any of theirs. And they drank, and were merry with him.', pt: 'E ele tomou e lhes enviou porções de diante de si; mas a porção de Benjamim era cinco vezes maior do que a de qualquer deles. E beberam e se alegraram com ele.' },
  ],
  44: [
    { v: 1, en: 'And he commanded the steward of his house, saying, Fill the men\'s sacks with food, as much as they can carry, and put every man\'s money in his sack\'s mouth.', pt: 'E ordenou ao mordomo da sua casa: Enchei os sacos dos homens de alimento, tanto quanto possam carregar, e ponde o dinheiro de cada um na boca do seu saco.' },
    { v: 2, en: 'And put my cup, the silver cup, in the sack\'s mouth of the youngest, and his corn money. And he did according to the word that Joseph had spoken.', pt: 'E pondes o meu cálice, o cálice de prata, na boca do saco do mais novo, e o dinheiro do seu grão. E ele fez segundo a palavra que José havia dito.' },
    { v: 3, en: 'As soon as the morning was light, the men were sent away, they and their asses.', pt: 'Logo que amanheceu, os homens foram mandados embora, eles e os seus jumentos.' },
    { v: 4, en: 'And when they were gone out of the city, and not yet far off, Joseph said unto his steward, Up, follow after the men; and when thou dost overtake them, say unto them, Wherefore have ye rewarded evil for good?', pt: 'Quando tinham saído da cidade e não estavam ainda longe, José disse ao seu mordomo: Levanta-te, segue atrás dos homens; e quando os alcançares, dize-lhes: Por que recompensastes o mal pelo bem?' },
    { v: 5, en: 'Is not this it in which my lord drinketh, and whereby indeed he divineth? ye have done evil in so doing.', pt: 'Não é este o cálice em que o meu senhor bebe, e pelo qual ele de fato advinha? Fizestes mal em assim fazer.' },
    { v: 6, en: 'And he overtook them, and he spake unto them these same words.', pt: 'E os alcançou, e lhes falou essas mesmas palavras.' },
    { v: 7, en: 'And they said unto him, Wherefore saith my lord these words? God forbid that thy servants should do according to this thing:', pt: 'E eles lhe disseram: Por que diz meu senhor essas palavras? Longe de nós que os teus servos façam tal coisa.' },
    { v: 8, en: 'Behold, the money, which we found in our sacks\' mouths, we brought again unto thee out of the land of Canaan: how then should we steal out of thy lord\'s house silver or gold?', pt: 'Eis que o dinheiro que achamos nas bocas dos nossos sacos, tornamos a te trazer da terra de Canaã; como, pois, roubaríamos da casa do teu senhor prata ou ouro?' },
    { v: 9, en: 'With whomsoever of thy servants it be found, both let him die, and we also will be my lord\'s bondmen.', pt: 'Com qualquer dos teus servos em que for achado, que morra; e também nós seremos servos do meu senhor.' },
    { v: 10, en: 'And he said, Now also let it be according unto your words: he with whom it is found shall be my servant; and ye shall be blameless.', pt: 'E ele disse: Agora também seja segundo as vossas palavras; aquele com quem for achado será meu servo; e vós sereis inocentes.' },
    { v: 11, en: 'Then they speedily took down every man his sack to the ground, and opened every man his sack.', pt: 'Então rapidamente cada um abaixou o seu saco em terra, e cada um abriu o seu saco.' },
    { v: 12, en: 'And he searched, and began at the eldest, and left at the youngest: and the cup was found in Benjamin\'s sack.', pt: 'E ele revistou, e começou pelo mais velho e terminou no mais novo; e o cálice foi achado no saco de Benjamim.' },
    { v: 13, en: 'Then they rent their clothes, and laded every man his ass, and returned to the city.', pt: 'Então eles rasgaram as suas vestes, e cada um carregou o seu jumento, e voltaram à cidade.' },
    { v: 14, en: 'And Judah and his brethren came to Joseph\'s house; for he was yet there: and they fell before him on the ground.', pt: 'E Judá e seus irmãos foram à casa de José; pois ele ainda estava lá; e se lançaram em terra diante dele.' },
    { v: 15, en: 'And Joseph said unto them, What deed is this that ye have done? wot ye not that such a man as I can certainly divine?', pt: 'E José lhes disse: Que feito é este que fizestes? Não sabeis que um homem como eu certamente pode adivinhar?' },
    { v: 16, en: 'And Judah said, What shall we say unto my lord? what shall we speak? or how shall we clear ourselves? God hath found out the iniquity of thy servants: behold, we are my lord\'s servants, both we, and he also with whom the cup is found.', pt: 'E Judá disse: Que diremos a meu senhor? Que falaremos? Como nos justificaremos? Deus achou a iniquidade dos teus servos; eis que somos servos do meu senhor, tanto nós como aquele com quem o cálice foi achado.' },
    { v: 17, en: 'And he said, God forbid that I should do so: but the man in whose hand the cup is found, he shall be my servant; and as for you, get you up in peace unto your father.', pt: 'E ele disse: Longe de mim fazer isso; o homem em cuja mão foi achado o cálice, esse será meu servo; quanto a vós, subi em paz a vosso pai.' },
    { v: 18, en: 'Then Judah came near unto him, and said, Oh my lord, let thy servant, I pray thee, speak a word in my lord\'s ears, and let not thine anger burn against thy servant: for thou art even as Pharaoh.', pt: 'Então Judá se aproximou dele e disse: Ó meu senhor, que o teu servo fale, por favor, uma palavra aos ouvidos do meu senhor, e não se acenda a tua ira contra o teu servo; pois és como o próprio faraó.' },
    { v: 19, en: 'My lord asked his servants, saying, Have ye a father, or a brother?', pt: 'Meu senhor perguntou aos seus servos: Tendes pai ou irmão?' },
    { v: 20, en: 'And we said unto my lord, We have a father, an old man, and a child of his old age, a little one; and his brother is dead, and he alone is left of his mother, and his father loveth him.', pt: 'E dissemos a meu senhor: Temos pai, um ancião, e um filho da sua velhice, pequeno; e o seu irmão está morto, e só ele ficou da sua mãe, e seu pai o ama.' },
    { v: 21, en: 'And thou saidst unto thy servants, Bring him down unto me, that I may set mine eyes upon him.', pt: 'E tu disseste aos teus servos: Trazei-o a mim, para que eu ponha os meus olhos sobre ele.' },
    { v: 22, en: 'And we said unto my lord, The lad cannot leave his father: for if he should leave his father, his father would die.', pt: 'E dissemos a meu senhor: O jovem não pode deixar seu pai; pois se ele deixasse seu pai, seu pai morreria.' },
    { v: 23, en: 'And thou saidst unto thy servants, Except your youngest brother come down with you, ye shall see my face no more.', pt: 'E tu disseste aos teus servos: Exceto se o vosso irmão mais novo descer convosco, não vereis mais a minha face.' },
    { v: 24, en: 'And it came to pass when we came up unto thy servant my father, we told him the words of my lord.', pt: 'E aconteceu que quando voltamos a teu servo, nosso pai, lhe contamos as palavras de meu senhor.' },
    { v: 25, en: 'And our father said, Go again, and buy us a little food.', pt: 'E nosso pai disse: Voltai e comprai-nos um pouco de alimento.' },
    { v: 26, en: 'And we said, We cannot go down: if our youngest brother be with us, then will we go down: for we may not see the man\'s face, except our youngest brother be with us.', pt: 'E dissemos: Não podemos descer; se o nosso irmão mais novo estiver conosco, então desceremos; pois não podemos ver a face do homem, exceto se o nosso irmão mais novo estiver conosco.' },
    { v: 27, en: 'And thy servant my father said unto us, Ye know that my wife bare me two sons:', pt: 'E teu servo, nosso pai, nos disse: Vós sabeis que minha mulher me deu dois filhos.' },
    { v: 28, en: 'And the one went out from me, and I said, Surely he is torn in pieces; and I saw him not since:', pt: 'E um saiu de junto de mim, e eu disse: Certamente foi despedaçado; e nunca mais o vi.' },
    { v: 29, en: 'And if ye take this also from me, and mischief befall him, ye shall bring down my gray hairs with sorrow to the grave.', pt: 'E se tomardes também este de junto de mim, e lhe acontecer algum mal, fareis descer as minhas cãs com tristeza ao sepulcro.' },
    { v: 30, en: 'Now therefore when I come to thy servant my father, and the lad be not with us; seeing that his life is bound up in the lad\'s life;', pt: 'Agora, portanto, quando eu vier a teu servo, meu pai, e o jovem não estiver conosco; visto que a sua vida está ligada à vida do jovem;' },
    { v: 31, en: 'It shall come to pass, when he seeth that the lad is not with us, that he will die: and thy servants shall bring down the gray hairs of thy servant our father with sorrow to the grave.', pt: 'acontecerá que quando ele vir que o jovem não está conosco, ele morrerá; e os teus servos farão descer as cãs de teu servo, nosso pai, com tristeza ao sepulcro.' },
    { v: 32, en: 'For thy servant became surety for the lad unto my father, saying, If I bring him not unto thee, then I shall bear the blame to my father for ever.', pt: 'Pois o teu servo tornou-se garante pelo jovem perante meu pai, dizendo: Se eu não te trouxer, serei culpado perante meu pai para sempre.' },
    { v: 33, en: 'Now therefore, I pray thee, let thy servant abide instead of the lad a bondman to my lord; and let the lad go up with his brethren.', pt: 'Agora, portanto, por favor, que o teu servo fique em lugar do jovem como servo do meu senhor; e que o jovem suba com os seus irmãos.' },
    { v: 34, en: 'For how shall I go up to my father, and the lad be not with me? lest peradventure I see the evil that shall come on my father.', pt: 'Pois como subirei a meu pai, e o jovem não estiver comigo? Para que não veja o mal que sobrevirá a meu pai.' },
  ],
  45: [
    { v: 1, en: 'Then Joseph could not refrain himself before all them that stood by him; and he cried, Cause every man to go out from me. And there stood no man with him, while Joseph made himself known unto his brethren.', pt: 'Então José não pôde mais se conter diante de todos que estavam junto dele; e exclamou: Fazei sair todo homem de junto de mim. E não ficou nenhum homem com ele quando José se deu a conhecer a seus irmãos.' },
    { v: 2, en: 'And he wept aloud: and the Egyptians and the house of Pharaoh heard.', pt: 'E chorou em alta voz; e os egípcios ouviram, e a casa do faraó ouviu.' },
    { v: 3, en: 'And Joseph said unto his brethren, I am Joseph; doth my father yet live? And his brethren could not answer him; for they were troubled at his presence.', pt: 'E José disse a seus irmãos: Sou José; meu pai ainda vive? E seus irmãos não lhe podiam responder; pois estavam perturbados diante dele.' },
    { v: 4, en: 'And Joseph said unto his brethren, Come near to me, I pray you. And they came near. And he said, I am Joseph your brother, whom ye sold into Egypt.', pt: 'E José disse a seus irmãos: Chegai-vos a mim, por favor. E eles se chegaram. E ele disse: Sou José, vosso irmão, que vendestes para o Egito.' },
    { v: 5, en: 'Now therefore be not grieved, nor angry with yourselves, that ye sold me hither: for God did send me before you to preserve life.', pt: 'Agora, pois, não vos entristeçais nem vos zangueis convosco por me haverdes vendido para cá; pois Deus me enviou adiante de vós para preservar a vida.' },
    { v: 6, en: 'For these two years hath the famine been in the land: and yet there are five years, in the which there shall neither be earing nor harvest.', pt: 'Pois já faz dois anos que a fome está na terra; e ainda há cinco anos em que não haverá lavoura nem colheita.' },
    { v: 7, en: 'And God sent me before you to preserve you a posterity in the earth, and to save your lives by a great deliverance.', pt: 'E Deus me enviou adiante de vós para vos preservar uma posteridade na terra, e para salvar-vos a vida por uma grande libertação.' },
    { v: 8, en: 'So now it was not you that sent me hither, but God: and he hath made me a father to Pharaoh, and lord of all his house, and a ruler throughout all the land of Egypt.', pt: 'Assim, não fostes vós que me enviastes para cá, mas Deus; e ele me fez pai para o faraó, senhor de toda a sua casa e governador em toda a terra do Egito.' },
    { v: 9, en: 'Haste ye, and go up to my father, and say unto him, Thus saith thy son Joseph, God hath made me lord of all Egypt: come down unto me, tarry not:', pt: 'Apressai-vos e subi a meu pai, e dizei-lhe: Assim diz o teu filho José: Deus me fez senhor de todo o Egito; desce a mim, não te demores.' },
    { v: 10, en: 'And thou shalt dwell in the land of Goshen, and thou shalt be near unto me, thou, and thy children, and thy children\'s children, and thy flocks, and thy herds, and all that thou hast:', pt: 'E habitarás na terra de Gósen, e estarás perto de mim, tu, teus filhos, os filhos de teus filhos, os teus rebanhos, o teu gado e tudo o que tens.' },
    { v: 11, en: 'And there will I nourish thee; for yet there are five years of famine; lest thou, and thy household, and all that thou hast, come to poverty.', pt: 'E ali te sustentarei; pois ainda há cinco anos de fome; para que não empobreceres tu, a tua família e tudo o que tens.' },
    { v: 12, en: 'And, behold, your eyes see, and the eyes of my brother Benjamin, that it is my mouth that speaketh unto you.', pt: 'E eis que os vossos olhos veem, e os olhos de meu irmão Benjamim, que é minha boca que vos fala.' },
    { v: 13, en: 'And ye shall tell my father of all my glory in Egypt, and of all that ye have seen; and ye shall haste and bring down my father hither.', pt: 'E contareis a meu pai toda a minha glória no Egito e tudo o que vistes; e apressai-vos e trazei meu pai aqui.' },
    { v: 14, en: 'And he fell upon his brother Benjamin\'s neck, and wept; and Benjamin wept upon his neck.', pt: 'E caiu no pescoço de Benjamim, seu irmão, e chorou; e Benjamim chorou no seu pescoço.' },
    { v: 15, en: 'Moreover he kissed all his brethren, and wept upon them: and after that his brethren talked with him.', pt: 'E beijou todos os seus irmãos e chorou sobre eles; e depois os seus irmãos falaram com ele.' },
    { v: 16, en: 'And the fame thereof was heard in Pharaoh\'s house, saying, Joseph\'s brethren are come: and it pleased Pharaoh well, and his servants.', pt: 'E a notícia foi ouvida na casa do faraó: Os irmãos de José vieram; e agradou ao faraó e aos seus servos.' },
    { v: 17, en: 'And Pharaoh said unto Joseph, Say unto thy brethren, This do ye; lade your beasts, and go, get you unto the land of Canaan;', pt: 'E o faraó disse a José: Dize a teus irmãos: Fazei isto; carregai os vossos animais e ide, chegai à terra de Canaã.' },
    { v: 18, en: 'And take your father and your households, and come unto me: and I will give you the good of the land of Egypt, and ye shall eat the fat of the land.', pt: 'E tomai vosso pai e as vossas famílias, e vinde a mim; e eu vos darei o melhor da terra do Egito, e comereis a gordura da terra.' },
    { v: 19, en: 'Now thou art commanded, this do ye; take you wagons out of the land of Egypt for your little ones, and for your wives, and bring your father, and come.', pt: 'E a ti é ordenado: Fazei isso; tomai carroças da terra do Egito para as vossas crianças e para as vossas mulheres, e trazei vosso pai e vinde.' },
    { v: 20, en: 'Also regard not your stuff; for the good of all the land of Egypt is yours.', pt: 'E não vos preocupeis com as vossas coisas; pois o melhor de toda a terra do Egito é vosso.' },
    { v: 21, en: 'And the children of Israel did so: and Joseph gave them wagons, according to the commandment of Pharaoh, and gave them provision for the way.', pt: 'E os filhos de Israel assim fizeram; e José lhes deu carroças, segundo o mandamento do faraó, e lhes deu provisão para o caminho.' },
    { v: 22, en: 'To all of them he gave each man changes of raiment; but to Benjamin he gave three hundred pieces of silver, and five changes of raiment.', pt: 'A todos deu mudas de roupa; mas a Benjamim deu trezentas peças de prata e cinco mudas de roupa.' },
    { v: 23, en: 'And to his father he sent after this manner; ten asses laden with the good things of Egypt, and ten she asses laden with corn and bread and meat for his father by the way.', pt: 'E a seu pai enviou da seguinte maneira: dez jumentos carregados com as melhores coisas do Egito, e dez jumentas carregadas com grão, pão e mantimentos para seu pai pelo caminho.' },
    { v: 24, en: 'So he sent his brethren away, and they departed: and he said unto them, See that ye fall not out by the way.', pt: 'Assim despediu os seus irmãos, e eles partiram; e lhes disse: Não brigeis pelo caminho.' },
    { v: 25, en: 'And they went up out of Egypt, and came into the land of Canaan unto Jacob their father,', pt: 'E subiram do Egito e chegaram à terra de Canaã, a Jacó, seu pai,' },
    { v: 26, en: 'And told him, saying, Joseph is yet alive, and he is governor over all the land of Egypt. And Jacob\'s heart fainted, for he believed them not.', pt: 'e lhe contaram: José ainda vive, e é governador sobre toda a terra do Egito. E o coração de Jacó desmaiou, pois não acreditou neles.' },
    { v: 27, en: 'And they told him all the words of Joseph, which he had said unto them: and when he saw the wagons which Joseph had sent to carry him, the spirit of Jacob their father revived:', pt: 'E lhe contaram todas as palavras de José, que havia dito a eles; e quando viu as carroças que José havia enviado para transportá-lo, o espírito de Jacó, pai deles, reviveu.' },
    { v: 28, en: 'And Israel said, It is enough; Joseph my son is yet alive: I will go and see him before I die.', pt: 'E Israel disse: É suficiente; José, meu filho, ainda vive; irei e o verei antes de morrer.' },
  ],
  46: [
    { v: 1, en: 'And Israel took his journey with all that he had, and came to Beersheba, and offered sacrifices unto the God of his father Isaac.', pt: 'E Israel partiu com tudo o que tinha, e chegou a Berseba, e ofereceu sacrifícios ao Deus de seu pai Isaque.' },
    { v: 2, en: 'And God spake unto Israel in the visions of the night, and said, Jacob, Jacob. And he said, Here am I.', pt: 'E Deus falou a Israel em visões de noite, e disse: Jacó, Jacó. E ele disse: Eis-me aqui.' },
    { v: 3, en: 'And he said, I am God, the God of thy father: fear not to go down into Egypt; for I will there make of thee a great nation:', pt: 'E disse: Eu sou Deus, o Deus de teu pai; não temas descer ao Egito; pois ali farei de ti uma grande nação.' },
    { v: 4, en: 'I will go down with thee into Egypt; and I will also surely bring thee up again: and Joseph shall put his hand upon thine eyes.', pt: 'Descerei contigo ao Egito; e certamente te farei subir de novo; e José porá a sua mão sobre os teus olhos.' },
    { v: 5, en: 'And Jacob rose up from Beersheba: and the sons of Israel carried Jacob their father, and their little ones, and their wives, in the wagons which Pharaoh had sent to carry him.', pt: 'E Jacó se levantou de Berseba; e os filhos de Israel levaram Jacó, seu pai, e as suas crianças e as suas mulheres nas carroças que o faraó havia enviado para transportá-lo.' },
    { v: 6, en: 'And they took their cattle, and their goods, which they had gotten in the land of Canaan, and came into Egypt, Jacob, and all his seed with him:', pt: 'E tomaram o seu gado e os seus bens que haviam adquirido na terra de Canaã, e vieram ao Egito, Jacó e toda a sua descendência com ele.' },
    { v: 7, en: 'His sons, and his sons\' sons with him, his daughters, and his sons\' daughters, and all his seed brought he with him into Egypt.', pt: 'Os seus filhos e os filhos dos seus filhos com ele, as suas filhas e as filhas dos seus filhos, e toda a sua descendência trouxe com ele ao Egito.' },
    { v: 8, en: 'And these are the names of the children of Israel, which came into Egypt, Jacob and his sons: Reuben, Jacob\'s firstborn.', pt: 'E estes são os nomes dos filhos de Israel que vieram ao Egito, Jacó e seus filhos: Rúben, primogênito de Jacó.' },
    { v: 9, en: 'And the sons of Reuben; Hanoch, and Phallu, and Hezron, and Carmi.', pt: 'E os filhos de Rúben: Enoque, Falu, Esrom e Carmi.' },
    { v: 10, en: 'And the sons of Simeon; Jemuel, and Jamin, and Ohad, and Jachin, and Zohar, and Shaul the son of a Canaanitish woman.', pt: 'E os filhos de Simeão: Jemuel, Jamim, Oade, Jaquim, Zoar e Saul, filho de uma mulher cananeia.' },
    { v: 11, en: 'And the sons of Levi; Gershon, Kohath, and Merari.', pt: 'E os filhos de Levi: Gérson, Coate e Merari.' },
    { v: 12, en: 'And the sons of Judah; Er, and Onan, and Shelah, and Pharez, and Zarah: but Er and Onan died in the land of Canaan. And the sons of Pharez were Hezron and Hamul.', pt: 'E os filhos de Judá: Er, Onã, Selá, Fares e Zerá; mas Er e Onã morreram na terra de Canaã. E os filhos de Fares foram Esrom e Hamul.' },
    { v: 13, en: 'And the sons of Issachar; Tola, and Phuvah, and Job, and Shimron.', pt: 'E os filhos de Issacar: Tolá, Fuvá, Jó e Sinrom.' },
    { v: 14, en: 'And the sons of Zebulun; Sered, and Elon, and Jahleel.', pt: 'E os filhos de Zebulom: Serede, Elom e Jaleel.' },
    { v: 15, en: 'These be the sons of Leah, which she bare unto Jacob in Padanaram, with his daughter Dinah: all the souls of his sons and his daughters were thirty and three.', pt: 'Estes são os filhos de Lia, que ela deu a Jacó na Padã-Arã, com a sua filha Diná; todas as almas dos seus filhos e das suas filhas eram trinta e três.' },
    { v: 16, en: 'And the sons of Gad; Ziphion, and Haggi, Shuni, and Ezbon, Eri, and Arodi, and Areli.', pt: 'E os filhos de Gade: Zifiom, Hagi, Suni, Esbom, Eri, Arodi e Areli.' },
    { v: 17, en: 'And the sons of Asher; Jimnah, and Ishuah, and Isui, and Beriah, and Serah their sister: and the sons of Beriah; Heber, and Malchiel.', pt: 'E os filhos de Aser: Imna, Isuá, Isui e Beria, e Sera, irmã deles; e os filhos de Beria: Heber e Malquiel.' },
    { v: 18, en: 'These are the sons of Zilpah, whom Laban gave to Leah his daughter, and these she bare unto Jacob, even sixteen souls.', pt: 'Estes são os filhos de Zilpa, que Labão deu a Lia, sua filha, e ela os deu à luz para Jacó, dezesseis almas.' },
    { v: 19, en: 'The sons of Rachel Jacob\'s wife; Joseph, and Benjamin.', pt: 'Os filhos de Raquel, mulher de Jacó: José e Benjamim.' },
    { v: 20, en: 'And unto Joseph in the land of Egypt were born Manasseh and Ephraim, which Asenath the daughter of Potipherah priest of On bare unto him.', pt: 'E a José na terra do Egito nasceram Manassés e Efraim, que Asenet, filha de Potífera, sacerdote de Om, lhe deu à luz.' },
    { v: 21, en: 'And the sons of Benjamin were Belah, and Becher, and Ashbel, Gera, and Naaman, Ehi, and Rosh, Muppim, and Huppim, and Ard.', pt: 'E os filhos de Benjamim foram Belá, Bequer, Asbel, Gerá, Naamã, Eí, Ros, Mupim, Hupim e Arde.' },
    { v: 22, en: 'These are the sons of Rachel, which were born to Jacob: all the souls were fourteen.', pt: 'Estes são os filhos de Raquel que nasceram a Jacó; todas as almas foram quatorze.' },
    { v: 23, en: 'And the sons of Dan; Hushim.', pt: 'E os filhos de Dã: Husim.' },
    { v: 24, en: 'And the sons of Naphtali; Jahzeel, and Guni, and Jezer, and Shillem.', pt: 'E os filhos de Naftali: Jazeel, Guni, Jezer e Silem.' },
    { v: 25, en: 'These are the sons of Bilhah, which Laban gave unto Rachel his daughter, and she bare these unto Jacob: all the souls were seven.', pt: 'Estes são os filhos de Bila, que Labão deu a Raquel, sua filha, e ela os deu à luz a Jacó; todas as almas foram sete.' },
    { v: 26, en: 'All the souls that came with Jacob into Egypt, which came out of his loins, besides Jacob\'s sons\' wives, all the souls were threescore and six;', pt: 'Todas as almas que vieram com Jacó ao Egito, que saíram dos seus lombos, além das mulheres dos filhos de Jacó, todas as almas foram sessenta e seis.' },
    { v: 27, en: 'And the sons of Joseph, which were born him in Egypt, were two souls: all the souls of the house of Jacob, which came into Egypt, were threescore and ten.', pt: 'E os filhos de José que lhe nasceram no Egito eram duas almas; todas as almas da casa de Jacó que vieram ao Egito foram setenta.' },
    { v: 28, en: 'And he sent Judah before him unto Joseph, to direct his face unto Goshen; and they came into the land of Goshen.', pt: 'E enviou Judá adiante de si a José, para indicar o caminho a Gósen; e chegaram à terra de Gósen.' },
    { v: 29, en: 'And Joseph made ready his chariot, and went up to meet Israel his father, to Goshen, and presented himself unto him; and he fell on his neck, and wept on his neck a good while.', pt: 'E José preparou o seu carro e subiu para encontrar Israel, seu pai, em Gósen; e se apresentou a ele; e caiu no seu pescoço e chorou no seu pescoço por um bom tempo.' },
    { v: 30, en: 'And Israel said unto Joseph, Now let me die, since I have seen thy face, because thou art yet alive.', pt: 'E Israel disse a José: Agora, que eu morra, visto que vi o teu rosto, porque tu ainda vives.' },
    { v: 31, en: 'And Joseph said unto his brethren, and unto his father\'s house, I will go up, and shew Pharaoh, and say unto him, My brethren, and my father\'s house, which were in the land of Canaan, are come unto me;', pt: 'E José disse a seus irmãos e à casa de seu pai: Subirei e avisarei o faraó, e lhe direi: Meus irmãos e a casa de meu pai, que estavam na terra de Canaã, vieram a mim.' },
    { v: 32, en: 'And the men are shepherds, for their trade hath been to feed cattle; and they have brought their flocks, and their herds, and all that they have.', pt: 'E os homens são pastores, pois têm sido criadores de gado; e trouxeram os seus rebanhos, o seu gado e tudo o que têm.' },
    { v: 33, en: 'And it shall come to pass, when Pharaoh shall call you, and shall say, What is your occupation?', pt: 'E acontecerá que quando o faraó vos chamar e disser: Qual é a vossa ocupação?' },
    { v: 34, en: 'That ye shall say, Thy servants\' trade hath been about cattle from our youth even until now, both we, and also our fathers: that ye may dwell in the land of Goshen; for every shepherd is an abomination unto the Egyptians.', pt: 'Então direis: Os teus servos têm sido criadores de gado desde a nossa juventude até agora, tanto nós como nossos pais; para que habiteis na terra de Gósen; pois todo pastor é abominação aos egípcios.' },
  ],
  47: [
    { v: 1, en: 'Then Joseph came and told Pharaoh, and said, My father and my brethren, and their flocks, and their herds, and all that they have, are come out of the land of Canaan; and, behold, they are in the land of Goshen.', pt: 'Então José veio e disse ao faraó: Meu pai e meus irmãos, com os seus rebanhos, o seu gado e tudo o que têm, vieram da terra de Canaã; e eis que estão na terra de Gósen.' },
    { v: 2, en: 'And he took some of his brethren, even five men, and presented them unto Pharaoh.', pt: 'E tomou parte de seus irmãos, cinco homens, e os apresentou ao faraó.' },
    { v: 3, en: 'And Pharaoh said unto his brethren, What is your occupation? And they said unto Pharaoh, Thy servants are shepherds, both we, and also our fathers.', pt: 'E o faraó disse a seus irmãos: Qual é a vossa ocupação? E eles disseram ao faraó: Os teus servos são pastores, tanto nós como nossos pais.' },
    { v: 4, en: 'They said moreover unto Pharaoh, For to sojourn in the land are we come; for thy servants have no pasture for their flocks; for the famine is sore in the land of Canaan: now therefore, we pray thee, let thy servants dwell in the land of Goshen.', pt: 'E disseram mais ao faraó: Viemos para peregrinar na terra; pois os teus servos não têm pastagem para os seus rebanhos; porque a fome é rigorosa na terra de Canaã; agora, portanto, pedimos que os teus servos habitem na terra de Gósen.' },
    { v: 5, en: 'And Pharaoh spake unto Joseph, saying, Thy father and thy brethren are come unto thee:', pt: 'E o faraó disse a José: Teu pai e teus irmãos vieram a ti.' },
    { v: 6, en: 'The land of Egypt is before thee; in the best of the land make thy father and brethren to dwell; in the land of Goshen let them dwell: and if thou knowest any men of activity among them, then make them rulers over my cattle.', pt: 'A terra do Egito está diante de ti; na melhor da terra faze habitar teu pai e teus irmãos; na terra de Gósen que habitem; e se souberes que há homens capazes entre eles, então faze-os administradores do meu gado.' },
    { v: 7, en: 'And Joseph brought in Jacob his father, and set him before Pharaoh: and Jacob blessed Pharaoh.', pt: 'E José trouxe Jacó, seu pai, e o apresentou ao faraó; e Jacó abençoou o faraó.' },
    { v: 8, en: 'And Pharaoh said unto Jacob, How old art thou?', pt: 'E o faraó disse a Jacó: Quantos são os dias dos anos da tua vida?' },
    { v: 9, en: 'And Jacob said unto Pharaoh, The days of the years of my pilgrimage are an hundred and thirty years: few and evil have the days of the years of my life been, and have not attained unto the days of the years of the life of my fathers in the days of their pilgrimage.', pt: 'E Jacó disse ao faraó: Os dias dos anos da minha peregrinação são cento e trinta anos; poucos e maus foram os dias dos anos da minha vida, e não chegaram aos dias dos anos da vida de meus pais nos dias da sua peregrinação.' },
    { v: 10, en: 'And Jacob blessed Pharaoh, and went out from before Pharaoh.', pt: 'E Jacó abençoou o faraó e saiu de diante do faraó.' },
    { v: 11, en: 'And Joseph placed his father and his brethren, and gave them a possession in the land of Egypt, in the best of the land, in the land of Rameses, as Pharaoh had commanded.', pt: 'E José estabeleceu seu pai e seus irmãos e lhes deu uma possessão na terra do Egito, na melhor da terra, na terra de Ramessés, como o faraó havia mandado.' },
    { v: 12, en: 'And Joseph nourished his father, and his brethren, and all his father\'s household, with bread, according to their families.', pt: 'E José sustentou seu pai, seus irmãos e toda a casa de seu pai com pão, segundo as suas famílias.' },
    { v: 13, en: 'And there was no bread in all the land; for the famine was very sore, so that the land of Egypt and all the land of Canaan fainted by reason of the famine.', pt: 'E não havia pão em toda a terra; pois a fome era muito rigorosa, de modo que a terra do Egito e toda a terra de Canaã desfaleceram por causa da fome.' },
    { v: 14, en: 'And Joseph gathered up all the money that was found in the land of Egypt, and in the land of Canaan, for the corn which they bought: and Joseph brought the money into Pharaoh\'s house.', pt: 'E José recolheu todo o dinheiro que havia na terra do Egito e na terra de Canaã, pelo grão que compravam; e José trouxe o dinheiro à casa do faraó.' },
    { v: 15, en: 'And when money failed in the land of Egypt, and in the land of Canaan, all the Egyptians came unto Joseph, and said, Give us bread: for why should we die in thy presence? for the money faileth.', pt: 'E quando o dinheiro acabou na terra do Egito e na terra de Canaã, todos os egípcios vieram a José e disseram: Dá-nos pão; por que morreríamos diante de ti? pois o dinheiro acabou.' },
    { v: 16, en: 'And Joseph said, Give your cattle; and I will give you for your cattle, if money fail.', pt: 'E José disse: Dai o vosso gado; e eu vos darei pelo vosso gado, se o dinheiro acabou.' },
    { v: 17, en: 'And they brought their cattle unto Joseph: and Joseph gave them bread in exchange for horses, and for the flocks, and for the cattle of the herds, and for the asses: and he fed them with bread for all their cattle for that year.', pt: 'E trouxeram o seu gado a José; e José lhes deu pão em troca de cavalos, de ovelhas, de gado bovino e de jumentos; e os alimentou com pão por todo o seu gado naquele ano.' },
    { v: 18, en: 'When that year was ended, they came unto him the second year, and said unto him, We will not hide it from my lord, how that our money is spent; my lord also hath our herds of cattle; there is not ought left in the sight of my lord, but our bodies, and our lands:', pt: 'Quando aquele ano acabou, vieram a ele no segundo ano e lhe disseram: Não ocultaremos de meu senhor que o nosso dinheiro acabou; meu senhor também tem os nossos rebanhos de gado; não resta nada perante meu senhor senão os nossos corpos e as nossas terras.' },
    { v: 19, en: 'Wherefore shall we die before thine eyes, both we and our land? buy us and our land for bread, and we and our land will be servants unto Pharaoh: and give us seed, that we may live, and not die, that the land be not desolate.', pt: 'Por que morreríamos diante dos teus olhos, tanto nós como a nossa terra? Compra-nos a nós e à nossa terra por pão, e nós e a nossa terra seremos servos do faraó; e dá-nos semente para que vivamos e não morramos, e a terra não fique deserta.' },
    { v: 20, en: 'And Joseph bought all the land of Egypt for Pharaoh; for the Egyptians sold every man his field, because the famine prevailed over them: so the land became Pharaoh\'s.', pt: 'E José comprou toda a terra do Egito para o faraó; pois os egípcios venderam cada um o seu campo, porque a fome prevaleceu sobre eles; e assim a terra passou a ser do faraó.' },
    { v: 21, en: 'And as for the people, he removed them to cities from one end of the borders of Egypt even to the other end thereof.', pt: 'E quanto ao povo, ele os removeu para as cidades de uma extremidade das fronteiras do Egito à outra.' },
    { v: 22, en: 'Only the land of the priests bought he not; for the priests had a portion assigned them of Pharaoh, and did eat their portion which Pharaoh gave them: wherefore they sold not their lands.', pt: 'Somente a terra dos sacerdotes não comprou; pois os sacerdotes tinham uma porção designada pelo faraó, e comiam a sua porção que o faraó lhes dava; por isso não venderam as suas terras.' },
    { v: 23, en: 'Then Joseph said unto the people, Behold, I have bought you this day and your land for Pharaoh: lo, here is seed for you, and ye shall sow the land.', pt: 'Então José disse ao povo: Eis que hoje comprei a vós e à vossa terra para o faraó; eis aqui semente para vós, e semeareis a terra.' },
    { v: 24, en: 'And it shall come to pass in the increase, that ye shall give the fifth part unto Pharaoh, and four parts shall be your own, for seed of the field, and for your food, and for them of your households, and for food for your little ones.', pt: 'E acontecerá que do rendimento dareis a quinta parte ao faraó, e quatro partes serão vossas, para semente do campo, para o vosso alimento, para os das vossas casas e para alimento das vossas crianças.' },
    { v: 25, en: 'And they said, Thou hast saved our lives: let us find grace in the sight of my lord, and we will be Pharaoh\'s servants.', pt: 'E eles disseram: Tu salvaste as nossas vidas; que achemos graça aos olhos do meu senhor, e seremos servos do faraó.' },
    { v: 26, en: 'And Joseph made it a law over the land of Egypt unto this day, that Pharaoh should have the fifth part, except the land of the priests only, which became not Pharaoh\'s.', pt: 'E José fez disso uma lei sobre a terra do Egito até hoje, que o faraó teria a quinta parte; exceto somente a terra dos sacerdotes, que não passou a ser do faraó.' },
    { v: 27, en: 'And Israel dwelt in the land of Egypt, in the country of Goshen; and they had possessions therein, and grew, and multiplied exceedingly.', pt: 'E Israel habitou na terra do Egito, no país de Gósen; e tiveram possessões nele, e cresceram e se multiplicaram muito.' },
    { v: 28, en: 'And Jacob lived in the land of Egypt seventeen years: so the whole age of Jacob was an hundred forty and seven years.', pt: 'E Jacó viveu na terra do Egito dezessete anos; de modo que a idade total de Jacó foi de cento e quarenta e sete anos.' },
    { v: 29, en: 'And the time drew nigh that Israel must die: and he called his son Joseph, and said unto him, If now I have found grace in thy sight, put, I pray thee, thy hand under my thigh, and deal kindly and truly with me; bury me not, I pray thee, in Egypt:', pt: 'E chegou o tempo em que Israel devia morrer; e chamou seu filho José, e lhe disse: Se achei graça aos teus olhos, põe, por favor, a tua mão sob a minha coxa, e trata-me com bondade e fidelidade; não me enterres, por favor, no Egito.' },
    { v: 30, en: 'But I will lie with my fathers, and thou shalt carry me out of Egypt, and bury me in their buryingplace. And he said, I will do as thou hast said.', pt: 'Mas dormirei com meus pais, e me tirarás do Egito e me enterrarás na sua sepultura. E ele disse: Farei como disseste.' },
    { v: 31, en: 'And he said, Swear unto me. And he sware unto him. And Israel bowed himself upon the bed\'s head.', pt: 'E disse: Jura-me. E ele lhe jurou. E Israel se inclinou sobre a cabeceira da cama.' },
  ],
  48: [
    { v: 1, en: 'And it came to pass after these things, that one told Joseph, Behold, thy father is sick: and he took with him his two sons, Manasseh and Ephraim.', pt: 'Depois dessas coisas aconteceu que disseram a José: Eis que teu pai está doente; e ele tomou consigo os seus dois filhos, Manassés e Efraim.' },
    { v: 2, en: 'And one told Jacob, and said, Behold, thy son Joseph cometh unto thee: and Israel strengthened himself, and sat upon the bed.', pt: 'E disseram a Jacó: Eis que teu filho José vem a ti; e Israel se fortaleceu e se sentou na cama.' },
    { v: 3, en: 'And Jacob said unto Joseph, God Almighty appeared unto me at Luz in the land of Canaan, and blessed me,', pt: 'E Jacó disse a José: Deus Todo-Poderoso me apareceu em Luz, na terra de Canaã, e me abençoou,' },
    { v: 4, en: 'And said unto me, Behold, I will make thee fruitful, and multiply thee, and I will make of thee a multitude of people; and will give this land to thy seed after thee for an everlasting possession.', pt: 'e me disse: Eis que te farei fecundo, e te multiplicarei, e te tornarei uma multidão de povos; e darei esta terra à tua descendência depois de ti por possessão perpétua.' },
    { v: 5, en: 'And now thy two sons, Ephraim and Manasseh, which were born unto thee in the land of Egypt before I came unto thee into Egypt, are mine; as Reuben and Simeon, they shall be mine.', pt: 'E agora os teus dois filhos, Efraim e Manassés, que te nasceram na terra do Egito antes que eu viesse a ti ao Egito, são meus; como Rúben e Simeão, serão meus.' },
    { v: 6, en: 'And thy issue, which thou begettest after them, shall be thine, and shall be called after the name of their brethren in their inheritance.', pt: 'E a tua descendência que gerares depois deles será tua, e será chamada pelo nome de seus irmãos na sua herança.' },
    { v: 7, en: 'And as for me, when I came from Padan, Rachel died by me in the land of Canaan in the way, when yet there was but a little way to come unto Ephrath: and I buried her there in the way of Ephrath; the same is Bethlehem.', pt: 'E quanto a mim, quando eu vinha de Padã, Raquel morreu junto a mim na terra de Canaã, no caminho, quando ainda havia uma curta distância para chegar a Efrata; e a sepultei ali no caminho de Efrata, que é Belém.' },
    { v: 8, en: 'And Israel beheld Joseph\'s sons, and said, Who are these?', pt: 'E Israel viu os filhos de José, e disse: Quem são estes?' },
    { v: 9, en: 'And Joseph said unto his father, They are my sons, whom God hath given me in this place. And he said, Bring them, I pray thee, unto me, and I will bless them.', pt: 'E José disse a seu pai: São meus filhos, que Deus me deu aqui. E ele disse: Trazei-os a mim, por favor, e os abençoarei.' },
    { v: 10, en: 'Now the eyes of Israel were dim for age, so that he could not see. And he brought them near unto him; and he kissed them, and embraced them.', pt: 'Ora, os olhos de Israel estavam obscurecidos pela velhice, de modo que não podia ver. E os trouxe perto dele; e os beijou e os abraçou.' },
    { v: 11, en: 'And Israel said unto Joseph, I had not thought to see thy face: and, lo, God hath shewed me also thy seed.', pt: 'E Israel disse a José: Não esperava ver o teu rosto; e eis que Deus me mostrou também a tua descendência.' },
    { v: 12, en: 'And Joseph brought them out from between his knees, and he bowed himself with his face to the earth.', pt: 'E José os retirou de entre os seus joelhos, e se inclinou com o rosto em terra.' },
    { v: 13, en: 'And Joseph took them both, Ephraim in his right hand toward Israel\'s left hand, and Manasseh in his left hand toward Israel\'s right hand, and brought them near unto him.', pt: 'E José tomou os dois, Efraim em sua mão direita à esquerda de Israel, e Manassés em sua mão esquerda à direita de Israel, e os trouxe perto dele.' },
    { v: 14, en: 'And Israel stretched out his right hand, and laid it upon Ephraim\'s head, who was the younger, and his left hand upon Manasseh\'s head, guiding his hands wittingly; for Manasseh was the firstborn.', pt: 'E Israel estendeu a sua mão direita e a pôs sobre a cabeça de Efraim, que era o mais novo, e a sua mão esquerda sobre a cabeça de Manassés, cruzando as suas mãos intencionalmente; pois Manassés era o primogênito.' },
    { v: 15, en: 'And he blessed Joseph, and said, God, before whom my fathers Abraham and Isaac did walk, the God which fed me all my life long unto this day,', pt: 'E abençoou José e disse: O Deus diante de quem andaram meus pais Abraão e Isaque, o Deus que me apascentou durante toda a minha vida até este dia,' },
    { v: 16, en: 'The Angel which redeemed me from all evil, bless the lads; and let my name be named on them, and the name of my fathers Abraham and Isaac; and let them grow into a multitude in the midst of the earth.', pt: 'O Anjo que me redimiu de todo o mal, abençoe os jovens; e o meu nome seja nomeado sobre eles, e o nome de meus pais Abraão e Isaque; e que se multipliquem em grande número no meio da terra.' },
    { v: 17, en: 'And when Joseph saw that his father laid his right hand upon the head of Ephraim, it displeased him: and he held up his father\'s hand, to remove it from Ephraim\'s head unto Manasseh\'s head.', pt: 'E quando José viu que seu pai pôs a sua mão direita sobre a cabeça de Efraim, desagradou-lhe; e tomou a mão de seu pai para removê-la da cabeça de Efraim para a cabeça de Manassés.' },
    { v: 18, en: 'And Joseph said unto his father, Not so, my father: for this is the firstborn; put thy right hand upon his head.', pt: 'E José disse a seu pai: Não assim, meu pai; pois este é o primogênito; põe a tua mão direita sobre a sua cabeça.' },
    { v: 19, en: 'And his father refused, and said, I know it, my son, I know it: he also shall become a people, and he also shall be great: but truly his younger brother shall be greater than he, and his seed shall become a multitude of nations.', pt: 'Mas seu pai recusou e disse: Eu sei, meu filho, eu sei; ele também se tornará um povo e também será grande; mas o seu irmão mais novo será maior do que ele, e a sua descendência se tornará uma multidão de nações.' },
    { v: 20, en: 'And he blessed them that day, saying, In thee shall Israel bless, saying, God make thee as Ephraim and as Manasseh: and he set Ephraim before Manasseh.', pt: 'E os abençoou naquele dia, dizendo: Em vós Israel abençoará, dizendo: Deus te faça como Efraim e como Manassés; e pôs Efraim antes de Manassés.' },
    { v: 21, en: 'And Israel said unto Joseph, Behold, I die: but God shall be with you, and bring you again unto the land of your fathers.', pt: 'E Israel disse a José: Eis que estou morrendo; mas Deus estará convosco e vos fará voltar à terra de vossos pais.' },
    { v: 22, en: 'Moreover I have given to thee one portion above thy brethren, which I took out of the hand of the Amorite with my sword and with my bow.', pt: 'Além disso, dei a ti uma porção acima dos teus irmãos, que tomei da mão do amorreu com a minha espada e com o meu arco.' },
  ],
  49: [
    { v: 1, en: 'And Jacob called unto his sons, and said, Gather yourselves together, that I may tell you that which shall befall you in the last days.', pt: 'E Jacó chamou seus filhos e disse: Ajuntai-vos, para que eu vos diga o que vos sucederá nos últimos dias.' },
    { v: 2, en: 'Gather yourselves together, and hear, ye sons of Jacob; and hearken unto Israel your father.', pt: 'Ajuntai-vos e ouvi, filhos de Jacó; e prestai atenção a Israel, vosso pai.' },
    { v: 3, en: 'Reuben, thou art my firstborn, my might, and the beginning of my strength, the excellency of dignity, and the excellency of power:', pt: 'Rúben, tu és o meu primogênito, meu vigor e o princípio da minha força, excelência em dignidade e excelência em poder.' },
    { v: 4, en: 'Unstable as water, thou shalt not excel; because thou wentest up to thy father\'s bed; then defiledst thou it: he went up to my couch.', pt: 'Instável como a água, não terás preeminência; porque subiste ao leito de teu pai; então o desonraste; subiu ao meu divã.' },
    { v: 5, en: 'Simeon and Levi are brethren; instruments of cruelty are in their habitations.', pt: 'Simeão e Levi são irmãos; instrumentos de crueldade são as suas armas.' },
    { v: 6, en: 'O my soul, come not thou into their secret; unto their assembly, mine honour, be not thou united: for in their anger they slew a man, and in their selfwill they digged down a wall.', pt: 'Ó minha alma, não entres nos seus conselhos secretos; à sua assembleia, ó minha honra, não te unas; pois na sua ira mataram homens, e na sua obstinação desjarretaram bois.' },
    { v: 7, en: 'Cursed be their anger, for it was fierce; and their wrath, for it was cruel: I will divide them in Jacob, and scatter them in Israel.', pt: 'Maldita seja a sua ira, porque foi feroz; e o seu furor, porque foi cruel; eu os dividirei em Jacó e os dispersarei em Israel.' },
    { v: 8, en: 'Judah, thou art he whom thy brethren shall praise: thy hand shall be in the neck of thine enemies; thy father\'s children shall bow down before thee.', pt: 'Judá, tu és aquele que teus irmãos louvarão; a tua mão estará no pescoço dos teus inimigos; os filhos de teu pai se inclinarão diante de ti.' },
    { v: 9, en: 'Judah is a lion\'s whelp: from the prey, my son, thou art gone up: he stooped down, he couched as a lion, and as an old lion; who shall rouse him up?', pt: 'Judá é um filhote de leão; da presa, meu filho, subiste; ele se abaixou, se deitou como um leão, e como uma leoa; quem o despertará?' },
    { v: 10, en: 'The sceptre shall not depart from Judah, nor a lawgiver from between his feet, until Shiloh come; and unto him shall the gathering of the people be.', pt: 'O cetro não se afastará de Judá, nem o legislador dentre os seus pés, até que venha Siló; e a ele a obediência dos povos.' },
    { v: 11, en: 'Binding his foal unto the vine, and his ass\'s colt unto the choice vine; he washed his garments in wine, and his clothes in the blood of grapes:', pt: 'Atando o seu jumentinho à vinha, e o filho do seu jumento à vinha escolhida; lavou as suas vestes no vinho, e as suas roupas no sangue das uvas.' },
    { v: 12, en: 'His eyes shall be red with wine, and his teeth white with milk.', pt: 'Os seus olhos serão vermelhos de vinho, e os seus dentes brancos de leite.' },
    { v: 13, en: 'Zebulun shall dwell at the haven of the sea; and he shall be for an haven of ships; and his border shall be unto Zidon.', pt: 'Zebulom habitará no porto do mar; e ele será um porto para navios; e o seu limite chegará até Sidom.' },
    { v: 14, en: 'Issachar is a strong ass couching down between two burdens:', pt: 'Issacar é um jumento forte, deitado entre os currais.' },
    { v: 15, en: 'And he saw that rest was good, and the land that it was pleasant; and bowed his shoulder to bear, and became a servant unto tribute.', pt: 'E viu que o descanso era bom, e que a terra era agradável; e curvou o ombro para carregar, e se tornou servo tributário.' },
    { v: 16, en: 'Dan shall judge his people, as one of the tribes of Israel.', pt: 'Dã julgará o seu povo, como uma das tribos de Israel.' },
    { v: 17, en: 'Dan shall be a serpent by the way, an adder in the path, that biteth the horse heels, so that his rider shall fall backward.', pt: 'Dã será uma serpente no caminho, um áspide na vereda, que morde os calcanhares do cavalo, de modo que o seu cavaleiro caia para trás.' },
    { v: 18, en: 'I have waited for thy salvation, O LORD.', pt: 'Eu espero pela tua salvação, ó Senhor.' },
    { v: 19, en: 'Gad, a troop shall overcome him: but he shall overcome at the last.', pt: 'Gade, um bando o atacará; mas ele os atacará pelo calcanhar.' },
    { v: 20, en: 'Out of Asher his bread shall be fat, and he shall yield royal dainties.', pt: 'De Aser, o seu pão será gordo, e ele produzirá delícias reais.' },
    { v: 21, en: 'Naphtali is a hind let loose: he giveth goodly words.', pt: 'Naftali é uma corça solta; ele profere palavras formosas.' },
    { v: 22, en: 'Joseph is a fruitful bough, even a fruitful bough by a well; whose branches run over the wall:', pt: 'José é um ramo frutífero, um ramo frutífero junto a uma fonte; os seus galhos se estendem sobre o muro.' },
    { v: 23, en: 'The archers have sorely grieved him, and shot at him, and hated him:', pt: 'Os flecheiros o atacaram amargamente, atiraram nele e o odiaram.' },
    { v: 24, en: 'But his bow abode in strength, and the arms of his hands were made strong by the hands of the mighty God of Jacob; (from thence is the shepherd, the stone of Israel:)', pt: 'Mas o seu arco ficou firme em força, e os braços das suas mãos foram fortalecidos pelas mãos do poderoso Deus de Jacó; (dali é o Pastor, a Pedra de Israel).' },
    { v: 25, en: 'Even by the God of thy father, who shall help thee; and by the Almighty, who shall bless thee with blessings of heaven above, blessings of the deep that lieth under, blessings of the breasts, and of the womb:', pt: 'Pelo Deus de teu pai, que te ajudará; e pelo Todo-Poderoso, que te abençoará com bênçãos do céu em cima, bênçãos do abismo que jaz em baixo, bênçãos dos seios e do ventre.' },
    { v: 26, en: 'The blessings of thy father have prevailed above the blessings of my progenitors unto the utmost bound of the everlasting hills: they shall be on the head of Joseph, and on the crown of the head of him that was separate from his brethren.', pt: 'As bênçãos de teu pai prevaleceram acima das bênçãos de meus progenitores até ao extremo limite dos montes eternos; elas estarão sobre a cabeça de José, e sobre o alto da cabeça daquele que foi separado de seus irmãos.' },
    { v: 27, en: 'Benjamin shall ravin as a wolf: in the morning he shall devour the prey, and at night he shall divide the spoil.', pt: 'Benjamim é um lobo que arrebata; de manhã devorará a presa, e à tarde repartirá o despojo.' },
    { v: 28, en: 'All these are the twelve tribes of Israel: and this is it that their father spake unto them, and blessed them; every one according to his blessing he blessed them.', pt: 'Estas são as doze tribos de Israel; e isto é o que seu pai lhes falou e os abençoou; a cada um segundo a sua bênção os abençoou.' },
    { v: 29, en: 'And he charged them, and said unto them, I am to be gathered unto my people: bury me with my fathers in the cave that is in the field of Ephron the Hittite,', pt: 'E lhes ordenou e lhes disse: Eu vou ser reunido ao meu povo; sepultai-me com meus pais na caverna que está no campo de Efrom, o heteu,' },
    { v: 30, en: 'In the cave that is in the field of Machpelah, which is before Mamre, in the land of Canaan, which Abraham bought with the field of Ephron the Hittite for a possession of a buryingplace.', pt: 'na caverna que está no campo de Macpela, que está diante de Manre, na terra de Canaã, que Abraão comprou com o campo de Efrom, o heteu, como possessão de sepultura.' },
    { v: 31, en: 'There they buried Abraham and Sarah his wife; there they buried Isaac and Rebekah his wife; and there I buried Leah.', pt: 'Ali sepultaram Abraão e Sara, sua mulher; ali sepultaram Isaque e Rebeca, sua mulher; e ali sepultei Lia.' },
    { v: 32, en: 'The purchase of the field and of the cave that is therein was from the children of Heth.', pt: 'A compra do campo e da caverna que está nele foi dos filhos de Hete.' },
    { v: 33, en: 'And when Jacob had made an end of commanding his sons, he gathered up his feet into the bed, and yielded up the ghost, and was gathered unto his people.', pt: 'E quando Jacó terminou de dar ordens a seus filhos, recolheu os seus pés na cama, expirou e foi reunido ao seu povo.' },
  ],
  50: [
    { v: 1, en: 'And Joseph fell upon his father\'s face, and wept upon him, and kissed him.', pt: 'E José se lançou sobre o rosto de seu pai, e chorou sobre ele e o beijou.' },
    { v: 2, en: 'And Joseph commanded his servants the physicians to embalm his father: and the physicians embalmed Israel.', pt: 'E José ordenou aos seus servos, os médicos, que embalsamassem seu pai; e os médicos embalsamaram Israel.' },
    { v: 3, en: 'And forty days were fulfilled for him; for so are fulfilled the days of those which are embalmed: and the Egyptians mourned for him threescore and ten days.', pt: 'E completaram-se quarenta dias para ele; pois assim se completam os dias dos que são embalsamados; e os egípcios o prantearam setenta dias.' },
    { v: 4, en: 'And when the days of his mourning were past, Joseph spake unto the house of Pharaoh, saying, If now I have found grace in your eyes, speak, I pray you, in the ears of Pharaoh, saying,', pt: 'E quando passaram os dias do pranto, José falou à casa do faraó: Se achei graça aos vossos olhos, falai, por favor, aos ouvidos do faraó,' },
    { v: 5, en: 'My father made me swear, saying, Lo, I die: in my grave which I have digged for me in the land of Canaan, there shalt thou bury me. Now therefore let me go up, I pray thee, and bury my father, and I will come again.', pt: 'dizendo: Meu pai me fez jurar, dizendo: Eis que estou morrendo; na minha sepultura que preparei para mim na terra de Canaã, ali me enterrarás. Agora, portanto, que eu suba, por favor, e enterre meu pai, e voltarei.' },
    { v: 6, en: 'And Pharaoh said, Go up, and bury thy father, according as he made thee swear.', pt: 'E o faraó disse: Sobe e enterra teu pai, conforme ele te fez jurar.' },
    { v: 7, en: 'And Joseph went up to bury his father: and with him went up all the servants of Pharaoh, the elders of his house, and all the elders of the land of Egypt,', pt: 'E José subiu para enterrar seu pai; e com ele subiram todos os servos do faraó, os anciãos da sua casa e todos os anciãos da terra do Egito,' },
    { v: 8, en: 'And all the house of Joseph, and his brethren, and his father\'s house: only their little ones, and their flocks, and their herds, they left in the land of Goshen.', pt: 'e toda a casa de José, seus irmãos e a casa de seu pai; somente as suas crianças, os seus rebanhos e o seu gado deixaram na terra de Gósen.' },
    { v: 9, en: 'And there went up with him both chariots and horsemen: and it was a very great company.', pt: 'E com ele subiram carros e cavaleiros; e era uma companhia muito grande.' },
    { v: 10, en: 'And they came to the threshingfloor of Atad, which is beyond Jordan, and there they mourned with a great and very sore lamentation: and he made a mourning for his father seven days.', pt: 'E chegaram à eira de Atade, que está além do Jordão, e ali prantearam com grande e muito amargo pranto; e ele fez luto por seu pai sete dias.' },
    { v: 11, en: 'And when the inhabitants of the land, the Canaanites, saw the mourning in the floor of Atad, they said, This is a grievous mourning to the Egyptians: wherefore the name of it was called Abelmizraim, which is beyond Jordan.', pt: 'E quando os habitantes da terra, os cananeus, viram o pranto na eira de Atade, disseram: Este é um pranto grave para os egípcios; por isso o seu nome foi chamado Abel-Mizraim, que está além do Jordão.' },
    { v: 12, en: 'And his sons did unto him according as he commanded them:', pt: 'E seus filhos fizeram a ele conforme havia ordenado.' },
    { v: 13, en: 'For his sons carried him into the land of Canaan, and buried him in the cave of the field of Machpelah, which Abraham bought with the field for a possession of a buryingplace of Ephron the Hittite, before Mamre.', pt: 'Pois seus filhos o levaram à terra de Canaã e o sepultaram na caverna do campo de Macpela, que Abraão comprou com o campo para possessão de sepultura de Efrom, o heteu, diante de Manre.' },
    { v: 14, en: 'And Joseph returned into Egypt, he, and his brethren, and all that went up with him to bury his father, after he had buried his father.', pt: 'E José voltou ao Egito, ele, seus irmãos e todos que subiram com ele para enterrar seu pai, depois de ter enterrado seu pai.' },
    { v: 15, en: 'And when Joseph\'s brethren saw that their father was dead, they said, Joseph will peradventure hate us, and will certainly requite us all the evil which we did unto him.', pt: 'E quando os irmãos de José viram que seu pai estava morto, disseram: Talvez José nos odeie e certamente nos retribuirá todo o mal que lhe fizemos.' },
    { v: 16, en: 'And they sent a messenger unto Joseph, saying, Thy father did command before he died, saying,', pt: 'E enviaram um mensageiro a José, dizendo: Teu pai ordenou antes de morrer:' },
    { v: 17, en: 'So shall ye say unto Joseph, Forgive, I pray thee now, the trespass of thy brethren, and their sin; for they did unto thee evil: and now, we pray thee, forgive the trespass of the servants of the God of thy father. And Joseph wept when they spake unto him.', pt: 'Assim direis a José: Perdoa, por favor, a transgressão dos teus irmãos e o seu pecado; pois te fizeram mal; agora, por favor, perdoa a transgressão dos servos do Deus de teu pai. E José chorou quando lhe falaram.' },
    { v: 18, en: 'And his brethren also went and fell down before his face; and they said, Behold, we be thy servants.', pt: 'E seus irmãos também foram e se lançaram diante dele; e disseram: Eis que somos teus servos.' },
    { v: 19, en: 'And Joseph said unto them, Fear not: for am I in the place of God?', pt: 'E José lhes disse: Não tenhais medo; pois estou eu no lugar de Deus?' },
    { v: 20, en: 'But as for you, ye thought evil against me; but God meant it unto good, to bring to pass, as it is this day, to save much people alive.', pt: 'Vós pensastes o mal contra mim; mas Deus o pensou para o bem, para fazer como neste dia, salvar muita gente com vida.' },
    { v: 21, en: 'Now therefore fear ye not: I will nourish you, and your little ones. And he comforted them, and spake kindly unto them.', pt: 'Agora, portanto, não tenhais medo; eu vos sustentarei a vós e às vossas crianças. E os consolou e lhes falou ao coração.' },
    { v: 22, en: 'And Joseph dwelt in Egypt, he, and his father\'s house: and Joseph lived an hundred and ten years.', pt: 'E José habitou no Egito, ele e a casa de seu pai; e José viveu cento e dez anos.' },
    { v: 23, en: 'And Joseph saw Ephraim\'s children of the third generation: the children also of Machir the son of Manasseh were brought up upon Joseph\'s knees.', pt: 'E José viu os filhos de Efraim até a terceira geração; também os filhos de Maquir, filho de Manassés, foram criados nos joelhos de José.' },
    { v: 24, en: 'And Joseph said unto his brethren, I die: and God will surely visit you, and bring you out of this land unto the land which he sware to Abraham, to Isaac, and to Jacob.', pt: 'E José disse a seus irmãos: Estou morrendo; e Deus certamente vos visitará e vos fará sair desta terra à terra que jurou a Abraão, a Isaque e a Jacó.' },
    { v: 25, en: 'And Joseph took an oath of the children of Israel, saying, God will surely visit you, and ye shall carry up my bones from hence.', pt: 'E José fez os filhos de Israel jurarem, dizendo: Deus certamente vos visitará, e vós levareis os meus ossos daqui.' },
    { v: 26, en: 'So Joseph died, being an hundred and ten years old: and they embalmed him, and he was put in a coffin in Egypt.', pt: 'Assim morreu José, com cento e dez anos de idade; e o embalsamaram, e foi posto num caixão no Egito.' },
  ],
};
